    // =========================================================
    // DASHBOARD LANGUAGE
    // =========================================================
    function sanitizeDashboardLanguage(v) {
        const s = String(v || "").trim().toLowerCase();
        return s === "fr" ? "fr" : "en";
    }

    function toBool(v) {
        return v === true;
    }

    const dashboardLanguage = sanitizeDashboardLanguage(processedData.dashboard_language || "en");
    const dashboardCustomCardsInstalled = toBool(processedData.dashboard_custom_cards_installed);

    function sanitizePremiumDashboardMode(v) {
        const s = String(v || "legacy").trim().toLowerCase();
        if (["html", "new", "nouveau", "modular", "modulaire"].includes(s)) return "html";
        if (["both", "all", "les_deux", "deux"].includes(s)) return "both";
        return "legacy";
    }

