    // =========================================================
    // PAYLOAD DE SORTIE - enrichissement premium/dashboard
    // =========================================================
    if (!msg.payload || typeof msg.payload !== "object") {
        msg.payload = {};
    }

    msg.payload.dashboardLanguage = dashboardLanguage;
    msg.payload.dashboardCustomCardsInstalled = dashboardCustomCardsInstalled;
