const text = (msg.status?.text || '').toLowerCase().trim();
const source = msg.status?.source?.name || msg.status?.source?.id || 'mqtt';

const last = context.get('last_text');
if (last === text) return null;
context.set('last_text', text);

// Très important : tester "disconnected" AVANT "connected"
if (text.includes('disconnected')) {
    node.warn(`❌ MQTT broker disconnected [${source}]`);
} else if (text.includes('connected')) {
    node.warn(`✅ MQTT broker connected [${source}]`);
} else if (text.includes('connecting') || text.includes('reconnect')) {
    node.warn(`⚠️ MQTT broker reconnecting [${source}]`);
} else {
    node.warn(`ℹ️ MQTT broker status [${source}]: ${msg.status?.text || 'unknown'}`);
}

return msg;

const interfaces = msg.payload?.networkInterfaces || {};
let ip = null;
let chosenIf = null;

const ignorePrefixes = ["lo", "docker", "veth", "br-", "hassio"];
const ignoreExact = ["lo", "docker0", "hassio"];

for (const [ifName, entries] of Object.entries(interfaces)) {
    if (
        ignoreExact.includes(ifName) ||
        ignorePrefixes.some(prefix => ifName.startsWith(prefix))
    ) {
        continue;
    }

    for (const entry of entries) {
        if (
            entry.family === "IPv4" &&
            entry.internal === false &&
            entry.address &&
            !entry.address.startsWith("127.") &&
            !entry.address.startsWith("169.254.")
        ) {
            ip = entry.address;
            chosenIf = ifName;
            break;
        }
    }

    if (ip) break;
}

if (!ip) {
    for (const [ifName, entries] of Object.entries(interfaces)) {
        for (const entry of entries) {
            if (
                entry.family === "IPv4" &&
                entry.internal === false &&
                entry.address &&
                !entry.address.startsWith("127.")
            ) {
                ip = entry.address;
                chosenIf = ifName;
                break;
            }
        }
        if (ip) break;
    }
}

if (!ip) {
    node.error("No valid IPv4 network address found.", msg);
    return null;
}

msg.dashboard_url = `http://${ip}:1891/endpoint/dashboard/`;
msg.detected_interface = chosenIf;
msg.detected_ip = ip;

node.warn(`⏩ Interface detected: ${chosenIf}`);
node.warn(`⏩ Dashboard URL for Standalone version: ${msg.dashboard_url}`);
node.warn(`⏩ Please do not use with HAOS, only in standalone mode (executable for Windows or Linux)`);
node.warn(`⏩ If you still wish to use it in HAOS, use the \"iFrame\" card with the above address`);

return msg;

const crypto = global.get("crypto");
const fs = global.get("fs");
const path = global.get("path");

function normStr(v) {
    return (v ?? "").toString().trim();
}

function generateInstallId() {
    if (crypto && typeof crypto.randomUUID === "function") {
        return crypto.randomUUID();
    }

    return "sjk-" +
        Date.now().toString(36) +
        "-" +
        Math.random().toString(36).slice(2, 10);
}

const installDir = "/data";
const installFile = "/data/smart_jkbms_premium.json";

let installId = "";
let payload = {};

try {
    if (!fs.existsSync(installDir)) {
        fs.mkdirSync(installDir, { recursive: true });
    }

    if (fs.existsSync(installFile)) {
        const raw = fs.readFileSync(installFile, "utf8");
        payload = JSON.parse(raw || "{}");
    }

    installId = normStr(payload.install_id);

    if (!installId) {
        installId = generateInstallId();
        payload.install_id = installId;
        fs.writeFileSync(installFile, JSON.stringify(payload, null, 2), "utf8");
    }

    global.set("premium.install_id", installId);
    global.set("premium.storage_file", installFile);

    node.status({ fill: "green", shape: "dot", text: "install_id ready" });

    msg.payload = {
        install_id: installId,
        file: installFile
    };

    return msg;

} catch (err) {
    node.error("PREMIUM STORAGE INIT error: " + err.message, msg);
    node.status({ fill: "red", shape: "ring", text: "storage init error" });
    return null;
}

