const crypto = global.get("crypto");

function normStr(v) {
    return (v ?? "").toString().trim();
}

function b64urlToBuffer(input) {
    let s = String(input || "").trim()
        .replace(/-/g, "+")
        .replace(/_/g, "/");

    while (s.length % 4) {
        s += "=";
    }

    return Buffer.from(s, "base64");
}

function safeJsonParseBuffer(buf) {
    return JSON.parse(buf.toString("utf8"));
}

function isBlankPublicKey(pem) {
    const s = String(pem || "");
    return (
        !s.includes("BEGIN PUBLIC KEY") ||
        s.includes("COLLER_ICI_LA_CLE_PUBLIQUE") ||
        s.includes("REMPLACE_PAR_TA_CLE_PUBLIQUE")
    );
}

// =========================================================
// À REMPLACER PAR LA CLÉ PUBLIQUE AFFICHÉE PAR TA VM ORACLE
// Interface VM : bouton "Afficher clé publique"
// ou API : /api/public-key
// =========================================================

const PUBLIC_KEY_PEM = `-----BEGIN PUBLIC KEY-----
MCowBQYDK2VwAyEANx4f2OpAbYfWEAGc87l4qX7Hf2nyJCih8nljqLBoMzA=
-----END PUBLIC KEY-----`;

// Produit attendu pour ce module
const EXPECTED_PRODUCT = "smartphoton-jkbms";
const EXPECTED_SYSTEM = "jkbms_rs485";
const EXPECTED_TIER = "premium";

const premiumKey = normStr(global.get("premium.key"));
const installId = normStr(global.get("premium.install_id"));

const defaultFeatures = {
    mqtt_core: true,
    ha_discovery: true,
    multi_bms: false,
    dashboard_premium: false,
    csv_export: false,
    cycles_soh: false,
    cell_details: false,
    advanced_info: false
};

let premiumActive = false;
let premiumStatus = "missing_key";
let premiumTier = null;
let premiumPayload = null;
let premiumFeatures = { ...defaultFeatures };
let licenseId = null;
let keyId = null;
let customer = null;
let issuedAt = null;
let expiresAt = null;

function verifySpv2License(license) {
    const raw = String(license || "").trim();
    const parts = raw.split(".");

    if (parts.length !== 3 || parts[0] !== "SPV2") {
        throw new Error("invalid_format");
    }

    const payloadB64 = parts[1];
    const signature = b64urlToBuffer(parts[2]);

    const ok = crypto.verify(
        null,
        Buffer.from(payloadB64, "utf8"),
        PUBLIC_KEY_PEM,
        signature
    );

    if (!ok) {
        throw new Error("invalid_signature");
    }

    return safeJsonParseBuffer(b64urlToBuffer(payloadB64));
}

function isExpiredDateOnly(expires) {
    const s = normStr(expires);
    if (!s) return false;

    // La VM utilise normalement YYYY-MM-DD.
    // On considère la licence valide jusqu'à la fin de cette date en UTC.
    let limit;
    if (/^\d{4}-\d{2}-\d{2}$/.test(s)) {
        limit = new Date(s + "T23:59:59.999Z");
    } else {
        limit = new Date(s);
    }

    if (Number.isNaN(limit.getTime())) {
        throw new Error("invalid_expiration");
    }

    return Date.now() > limit.getTime();
}

try {
    if (!crypto || typeof crypto.verify !== "function") {
        premiumStatus = "crypto_missing";
    } else if (isBlankPublicKey(PUBLIC_KEY_PEM)) {
        premiumStatus = "public_key_not_configured";
    } else if (!installId) {
        premiumStatus = "missing_install_id";
    } else if (!premiumKey) {
        premiumStatus = "missing_key";
    } else {
        const payload = verifySpv2License(premiumKey);

        if (Number(payload.v) !== 2) {
            premiumStatus = "invalid_payload_version";
        } else if (payload.iss !== "SmartPhoton") {
            premiumStatus = "invalid_issuer";
        } else if (payload.product !== EXPECTED_PRODUCT) {
            premiumStatus = "invalid_product";
        } else if (payload.system !== EXPECTED_SYSTEM) {
            premiumStatus = "invalid_system";
        } else if (payload.tier !== EXPECTED_TIER) {
            premiumStatus = "invalid_tier";
        } else if (normStr(payload.install_id) !== installId) {
            premiumStatus = "install_id_mismatch";
        } else if (isExpiredDateOnly(payload.expires_at)) {
            premiumStatus = "expired";
        } else {
            premiumActive = true;
            premiumStatus = "valid";
            premiumTier = payload.tier || EXPECTED_TIER;
            premiumPayload = payload;
            premiumFeatures = {
                ...defaultFeatures,
                ...(payload.features || {})
            };

            licenseId = payload.license_id || null;
            keyId = payload.key_id || null;
            customer = payload.customer || null;
            issuedAt = payload.issued_at || null;
            expiresAt = payload.expires_at || null;

            global.set("premium.last_valid", Date.now());
        }
    }
} catch (err) {
    premiumStatus = err.message || "invalid_license";
}

// Variables globales historiques conservées
global.set("premium.active", premiumActive);
global.set("premium.status", premiumStatus);
global.set("premium.tier", premiumTier);
global.set("premium.features", premiumFeatures);

// Nouvelles infos utiles
global.set("premium.payload", premiumPayload);
global.set("premium.license_id", licenseId);
global.set("premium.key_id", keyId);
global.set("premium.customer", customer);
global.set("premium.issued_at", issuedAt);
global.set("premium.expires_at", expiresAt);

// Compatibilité avec les noeuds qui lisent global.get("premium")
const premiumState = {
    install_id: installId || null,
    active: premiumActive,
    status: premiumActive ? "active" : premiumStatus,
    validation_status: premiumStatus,
    tier: premiumTier,
    license_id: licenseId,
    key_id: keyId,
    customer,
    issued_at: issuedAt,
    expires_at: expiresAt,
    features: premiumFeatures
};

global.set("premium", premiumState);

node.warn("JK PREMIUM STATE SPV2 -> " + JSON.stringify({
    install_id: premiumState.install_id,
    active: premiumState.active,
    status: premiumState.status,
    validation_status: premiumState.validation_status,
    tier: premiumState.tier,
    license_id: premiumState.license_id,
    key_id: premiumState.key_id,
    features: premiumState.features
}));

if (premiumActive) {
    node.status({
        fill: "green",
        shape: "dot",
        text: "premium valid SPV2"
    });
} else {
    node.status({
        fill: premiumStatus === "missing_key" ? "grey" : "yellow",
        shape: "ring",
        text: premiumStatus
    });
}

msg.payload = { premium: premiumState };
return msg;

// =========== BMS DATA PROCESSING - STABLE HA DISCOVERY VERSION ===========

// 0. Récupération adresse BMS et conversion en "master" si nécessaire
let bmsAdresse = msg.bms_numero;
let slaveIdStr;

if (typeof bmsAdresse === "string" && bmsAdresse.toLowerCase() === "master") {
    slaveIdStr = "master";
} else if (!isNaN(Number(bmsAdresse))) {
    if (Number(bmsAdresse) === 0) {
        slaveIdStr = "master";
    } else {
        slaveIdStr = String(Number(bmsAdresse));
    }
} else {
    slaveIdStr = "master";
}

var payload = msg.payload || {};
var baseTopic = "BMS_" + slaveIdStr;
var sensorDiscoveryPrefix = "homeassistant/sensor";
var binaryDiscoveryPrefix = "homeassistant/binary_sensor";
var deviceName = "BMS_" + slaveIdStr;
var deviceID = "BMS_" + slaveIdStr + "_device";

var topics = {};
var discoveryMsgs = [];

const discoveryKey = `discoverySent_BMS_${slaveIdStr}`;
let discoveryAlreadySent = flow.get(discoveryKey) || false;

const discoveredKeysStore = `discoveredKeys_BMS_${slaveIdStr}`;
let previousDiscoveredKeys = flow.get(discoveredKeysStore) || [];

// ------------------------------------------------------------------
// 1. Traitement des tensions de cellules
let cellCount = Number(flow.get(`jk_cell_count_BMS_${slaveIdStr}`)) || 16;
cellCount = Math.max(1, Math.min(cellCount, 16));
payload["cell_count_used_N"] = cellCount;

var cellVoltages = [];
var cellKeys = [];

for (let i = 1; i <= cellCount; i++) {
    let key = `Cell_${i}_volt_V`;
    let voltage = Number(payload[key]);
    if (Number.isFinite(voltage) && voltage > 0) {
        cellVoltages.push(voltage);
        cellKeys.push(key);
    }
}

if (cellVoltages.length > 0) {
    var cellAvgVolt = cellVoltages.reduce((sum, v) => sum + v, 0) / cellVoltages.length;
    var cellMaxVolt = Math.max(...cellVoltages);
    var cellMinVolt = Math.min(...cellVoltages);
    var cellDeltaVolt = cellMaxVolt - cellMinVolt;

    var maxVoltIndex = cellKeys[cellVoltages.indexOf(cellMaxVolt)].match(/Cell_(\d+)/)[1];
    var minVoltIndex = cellKeys[cellVoltages.indexOf(cellMinVolt)].match(/Cell_(\d+)/)[1];

    payload["cell_voltage_average_V"]    = parseFloat(cellAvgVolt.toFixed(3));
    payload["cell_voltage_delta_V"]      = parseFloat(cellDeltaVolt.toFixed(3));
    payload["cell_voltage_max_number_N"] = parseInt(maxVoltIndex);
    payload["cell_voltage_min_number_N"] = parseInt(minVoltIndex);
    payload["cell_voltage_min_value_V"]  = parseFloat(cellMinVolt.toFixed(3));
    payload["cell_voltage_max_value_V"]  = parseFloat(cellMaxVolt.toFixed(3));
} else {
    payload["cell_voltage_average_V"]    = 0;
    payload["cell_voltage_delta_V"]      = 0;
    payload["cell_voltage_max_number_N"] = 0;
    payload["cell_voltage_min_number_N"] = 0;
    payload["cell_voltage_min_value_V"]  = 0;
    payload["cell_voltage_max_value_V"]  = 0;
}

// ------------------------------------------------------------------
// 2. Formatage de Total_runtime_S
if (payload["Total_runtime_S"] !== undefined) {
    var totalSeconds = parseInt(payload["Total_runtime_S"]);
    if (!isNaN(totalSeconds)) {
        var days = Math.floor(totalSeconds / 86400);
        var remainingSeconds = totalSeconds % 86400;
        var hours = Math.floor(remainingSeconds / 3600);
        var minutes = Math.floor((remainingSeconds % 3600) / 60);
        payload["Total_runtime_formatted_T"] = `${days}D${hours}H${minutes}M`;
    }
}

// ------------------------------------------------------------------
// 3. charge_status_N → texte lisible
if (payload["charge_status_N"] !== undefined) {
    var v = parseInt(payload["charge_status_N"]);
    var txt = "Unknown";
    switch (v) {
        case 0:
        case 0x00:
            txt = "Bulk";
            break;
        case 1:
        case 0x01:
            txt = "Absorption";
            break;
        case 2:
        case 0x02:
            txt = "Float";
            break;
    }
    payload["charge_status_text_S"] = txt;
}

// ------------------------------------------------------------------
// 4. Formatage charge_status_time_S
if (payload["charge_status_time_S"] !== undefined) {
    var s = parseInt(payload["charge_status_time_S"]);
    if (!isNaN(s)) {
        var days = Math.floor(s / 86400);
        var rem = s % 86400;
        var hours = Math.floor(rem / 3600);
        var minutes = Math.floor((rem % 3600) / 60);
        var seconds = rem % 60;

        if (days > 0)
            payload["charge_status_time_formatted_T"] = `${days}D${hours}H${minutes}M`;
        else if (hours > 0)
            payload["charge_status_time_formatted_T"] = `${hours}H${minutes}M${seconds}S`;
        else if (minutes > 0)
            payload["charge_status_time_formatted_T"] = `${minutes}M${seconds}S`;
        else
            payload["charge_status_time_formatted_T"] = `${seconds}S`;
    }
}

// ------------------------------------------------------------------
// 5. Formatage Heating_B
if (payload["Heating_B"] !== undefined) {
    var heatingStatus = parseInt(payload["Heating_B"]);
    var heatingTxt = heatingStatus === 1 ? "ON" : "OFF";
    payload["Heating_status_text_S"] = heatingTxt;
}

// ------------------------------------------------------------------
// 6. Préparation topics + clés discovery
const allowedSuffixes = ["_V", "_A", "_W", "_T", "_Ah", "_R", "_P", "_S", "_B", "_N"];
let currentDiscoveredKeys = [];

for (var key in payload) {
    var hasValidSuffix = allowedSuffixes.some(s => key.endsWith(s));
    if (!hasValidSuffix) continue;

    var cleanKey = key.replace(/_[A-Z]+$/, "");
    currentDiscoveredKeys.push(cleanKey);

    var sensorTopic = `${baseTopic}/${cleanKey}`;
    topics[sensorTopic] = payload[key];
}

// Republie le discovery si nouvelles clés
let newKeys = currentDiscoveredKeys.filter(k => !previousDiscoveredKeys.includes(k));
let shouldSendDiscovery = !discoveryAlreadySent || newKeys.length > 0;

// ------------------------------------------------------------------
// 7. Génération discovery
for (var key in payload) {
    var hasValidSuffix = allowedSuffixes.some(s => key.endsWith(s));
    if (!hasValidSuffix) continue;

    var cleanKey = key.replace(/_[A-Z]+$/, "");
    var sensorTopic = `${baseTopic}/${cleanKey}`;

    if (!shouldSendDiscovery) continue;
    if (discoveryAlreadySent && !newKeys.includes(cleanKey)) continue;

    // Booléens -> binary_sensor
    if (key.endsWith("_B")) {
        var binaryConfigTopic = `${binaryDiscoveryPrefix}/${deviceID}_${cleanKey}/config`;

        var binaryConfigPayload = {
            name: cleanKey,
            unique_id: `${deviceID}_bms_${cleanKey}_v4`,
            state_topic: sensorTopic,
            payload_on: "1",
            payload_off: "0",
            device: {
                identifiers: [deviceID],
                name: deviceName,
                manufacturer: "Smartphoton-JK-BMS / ©JLM 2025-2026",
                model: "JK-BMS - RS485",
                sw_version: "3.5"
            },
            icon: "mdi:toggle-switch"
        };

        if (key === "Heating_B") {
            binaryConfigPayload.icon = "mdi:heating-coil";
        } else if (key === "Switch_Charge_B") {
            binaryConfigPayload.icon = "mdi:battery-charging";
        } else if (key === "Switch_Decharge_B") {
            binaryConfigPayload.icon = "mdi:battery-minus";
        } else if (key === "Balance_Action_B" || key === "Switch_Balance_B") {
            binaryConfigPayload.icon = "mdi:battery-sync";
        }

        // Force l'entity_id HA stable pour les binary_sensor data broadcasting
        binaryConfigPayload.object_id = `${baseTopic.toLowerCase()}_bms_${cleanKey}`;
        binaryConfigPayload.default_entity_id = `binary_sensor.${binaryConfigPayload.object_id}`;

        discoveryMsgs.push({
            topic: `${binaryDiscoveryPrefix}/${binaryConfigPayload.object_id}/config`,
            payload: JSON.stringify(binaryConfigPayload),
            retain: true
        });

        continue;
    }

    // Capteurs standards
    var configTopic = `${sensorDiscoveryPrefix}/${deviceID}_${cleanKey}/config`;

    var configPayload = {
        name: cleanKey,
        unique_id: `${deviceID}_bms_${cleanKey}_v4`,
        state_topic: sensorTopic,
        unit_of_measurement: "",
        entity_category: "diagnostic",
        device: {
            identifiers: [deviceID],
            name: deviceName,
            manufacturer: "Smartphoton-JK-BMS / ©JLM 2025-2026",
            model: "JK-BMS - RS485",
            sw_version: "3.5"
        }
    };

    if (key.endsWith("_V")) {
        configPayload.unit_of_measurement = "V";
        configPayload.device_class = "voltage";
        configPayload.state_class = "measurement";

        if (
            /^Cell_\d+_volt_V$/.test(key) ||
            key === "cell_voltage_average_V" ||
            key === "cell_voltage_delta_V" ||
            key === "cell_voltage_min_value_V" ||
            key === "cell_voltage_max_value_V"
        ) {
            configPayload.suggested_display_precision = 3;
        } else {
            configPayload.suggested_display_precision = 2;
        }
    }
    else if (key.endsWith("_Ah")) {
        configPayload.unit_of_measurement = "Ah";
        configPayload.state_class = "measurement";
    }
    else if (key.endsWith("_A")) {
        configPayload.unit_of_measurement = "A";
        configPayload.device_class = "current";
        configPayload.state_class = "measurement";
        configPayload.suggested_display_precision = 3;
    }
    else if (key.endsWith("_W")) {
        configPayload.unit_of_measurement = "W";
        configPayload.device_class = "power";
        configPayload.state_class = "measurement";
        configPayload.suggested_display_precision = 0;
    }
    else if (key.endsWith("_R")) {
        configPayload.unit_of_measurement = "Ω";
        configPayload.state_class = "measurement";
        configPayload.suggested_display_precision = 3;
    }
    else if (key.endsWith("_P")) {
        configPayload.unit_of_measurement = "%";
        configPayload.state_class = "measurement";
        configPayload.suggested_display_precision = 0;

        if (key.startsWith("SOC") || key.startsWith("SOH")) {
            configPayload.device_class = "battery";
        }
    }
    else if (key.endsWith("_T")) {
        if (key === "Total_runtime_formatted_T" || key === "charge_status_time_formatted_T") {
            configPayload.unit_of_measurement = "";
            configPayload.icon = "mdi:clock-time-eight-outline";
            delete configPayload.state_class;
            delete configPayload.device_class;
        } else {
            configPayload.unit_of_measurement = "°C";
            configPayload.device_class = "temperature";
            configPayload.state_class = "measurement";
            configPayload.suggested_display_precision = 1;
        }
    }
    else if (key.endsWith("_S")) {
        configPayload.unit_of_measurement = "";
        delete configPayload.state_class;
        delete configPayload.device_class;

        if (key === "charge_status_text_S") {
            configPayload.icon = "mdi:battery-charging";
        } else if (key === "Heating_status_text_S") {
            configPayload.icon = "mdi:heating-coil";
        } else {
            configPayload.icon = "mdi:text";
        }
    }
    else if (key.endsWith("_N")) {
        // IMPORTANT : index → pas une mesure
        delete configPayload.unit_of_measurement;
        delete configPayload.state_class;
        delete configPayload.device_class;

        configPayload.icon = "mdi:counter";
    }

    // Force l'entity_id HA stable pour les sensor data broadcasting
    configPayload.object_id = `${baseTopic.toLowerCase()}_bms_${cleanKey}`;
    configPayload.default_entity_id = `sensor.${configPayload.object_id}`;

    discoveryMsgs.push({
        topic: `${sensorDiscoveryPrefix}/${configPayload.object_id}/config`,
        payload: JSON.stringify(configPayload),
        retain: true
    });
}

// ------------------------------------------------------------------
// 8. Sortie
var outputMsgs = [];

if (shouldSendDiscovery) {
    outputMsgs = discoveryMsgs;
    flow.set(discoveryKey, true);
    flow.set(discoveredKeysStore, currentDiscoveredKeys);

    if (!discoveryAlreadySent) {
        node.warn(`✓ Discovery envoyé pour BMS ${slaveIdStr} (${discoveryMsgs.length} sensors)`);
    } else {
        node.warn(`✓ Discovery complémentaire envoyé pour BMS ${slaveIdStr} (${discoveryMsgs.length} new sensors)`);
    }
} else {
    node.debug(`Discovery déjà envoyé pour BMS ${slaveIdStr}`);
}

for (var t in topics) {
    outputMsgs.push({
        topic: t,
        payload: topics[t]
    });
}

return [outputMsgs];

// ========== SETUP TO MQTT - VERSION CORRIGÉE ET ROBUSTE ==========
// Buts :
// - Publier au premier passage
// - Republier si une valeur change
// - Republier si forçage demandé
// - Recréer les entités HA si elles ont disparu
// - Supporter l'apparition de nouvelles clés sans bloquer

// -----------------------------------------------------------------
// 1) Identification du BMS
// -----------------------------------------------------------------
let bmsAdresse = Number(msg.bms_numero);
let slaveIdStr = (bmsAdresse === 0) ? "master" : String(bmsAdresse);

if (!msg.payload || typeof msg.payload !== "object" || Array.isArray(msg.payload)) {
    node.warn(`Setup To MQTT ignoré: payload invalide pour BMS ${slaveIdStr}`);
    return null;
}

const payload = msg.payload;
const baseTopic = `BMS_${slaveIdStr}`;
const discoveryPrefix = "homeassistant";
const deviceName = `BMS_${slaveIdStr}`;
const deviceID = `${baseTopic}_device`;

// -----------------------------------------------------------------
// 2) Clés de contexte
// -----------------------------------------------------------------
const setupSentKey = `setupSent_BMS_${slaveIdStr}`;
const lastSetupKey = `lastSetup_BMS_${slaveIdStr}`;
const forceKeyFlow = `forceSetupRepublish_BMS_${slaveIdStr}`;
const forceAllKeyFlow = "forceSetupRepublishAll";

let setupAlreadySent = !!flow.get(setupSentKey);
let lastSetup = flow.get(lastSetupKey) || {};

const forceRepublish =
    msg.force_setup_republish === true ||
    flow.get(forceKeyFlow) === true ||
    flow.get(forceAllKeyFlow) === true ||
    global.get(forceKeyFlow) === true ||
    global.get(forceAllKeyFlow) === true;

// -----------------------------------------------------------------
// 3) Helpers
// -----------------------------------------------------------------
function formatBoolean(value) {
    if (typeof value === "boolean") {
        return value ? "True" : "False";
    }
    if (typeof value === "string") {
        const lowerVal = value.toLowerCase();
        if (lowerVal === "true") return "True";
        if (lowerVal === "false") return "False";
    }
    return value;
}

function normalizeValue(value) {
    if (typeof value === "boolean") {
        return value ? "True" : "False";
    }
    if (typeof value === "number") {
        // évite les faux changements 3.5 vs 3.500000
        return Number(value.toFixed(6));
    }
    if (typeof value === "string") {
        const lowerVal = value.toLowerCase();
        if (lowerVal === "true") return "True";
        if (lowerVal === "false") return "False";
        const asNum = Number(value);
        if (!Number.isNaN(asNum) && value.trim() !== "") {
            return Number(asNum.toFixed(6));
        }
        return value.trim();
    }
    return value;
}

function inferMeta(key) {
    // Quelques cas spécifiques conservés volontairement
    const custom = {
        max_charge_current_A: { unit: "A", min: 0, max: 600, step: 1 },
        max_discharge_current_S: { unit: "A", min: 0, max: 600, step: 1 }, // clé historique conservée
        max_balance_current_A: { unit: "A", min: 0, max: 10, step: 0.1 },
        total_battery_capacity_Ah: { unit: "Ah", min: 1, max: 2000, step: 1 },
        short_circuit_protection_delay_S: { unit: "s", min: 0, max: 5000, step: 1 },
        charge_overcurrent_protection_delay_S: { unit: "s", min: 0, max: 600, step: 1 },
        discharge_overcurrent_protection_delay_S: { unit: "s", min: 0, max: 600, step: 1 },
        charge_overcurrent_protection_recovery_time_S: { unit: "s", min: 0, max: 3600, step: 1 },
        discharge_overcurrent_protection_recovery_time_S: { unit: "s", min: 0, max: 3600, step: 1 },
        short_circuit_protection_recovery_time_S: { unit: "s", min: 0, max: 600, step: 1 },
        cell_count_N: { min: 1, max: 32, step: 1 },
        Device_address_N: { min: 0, max: 255, step: 1 }
    };

    if (custom[key]) return custom[key];

    if (key.endsWith("_V"))  return { unit: "V",  step: 0.001 };
    if (key.endsWith("_A"))  return { unit: "A",  step: 0.1 };
    if (key.endsWith("_Ah")) return { unit: "Ah", step: 1 };
    if (key.endsWith("_T"))  return { unit: "°C", step: 1 };
    if (key.endsWith("_S"))  return { unit: "s",  step: 1 };
    if (key.endsWith("_R"))  return { step: 0.001 };
    if (key.endsWith("_N"))  return { step: 1 };

    return {};
}

function createConfigPayload(key) {
    const cleanKey = key === "Device_address_N" ? "bms_device_address" : key.replace(/_[A-Z]+$/, "").toLowerCase();
    const entityType = key.endsWith("_B") ? "switch" : "number";
    const objectKey = key === "Device_address_N" ? "bms_device_address" : `bms_${cleanKey}`;

    const configPayload = {
        name: key === "Device_address_N" ? "BMS device address" : `BMS ${key.replace(/_[A-Z]+$/, "").replace(/_/g, " ")}`,
        unique_id: key === "Device_address_N" ? `${deviceID}_bms_device_address_v4` : `${deviceID}_bms_${cleanKey}_v4`,
        object_id: `${baseTopic.toLowerCase()}_${objectKey}`,
        default_entity_id: `${entityType}.${baseTopic.toLowerCase()}_${objectKey}`,
        state_topic: `${baseTopic}/control/${cleanKey}/state`,
        command_topic: `${baseTopic}/control/${cleanKey}/set`,
        entity_category: "config",
        device: {
            identifiers: [deviceID],
            name: deviceName,
            manufacturer: "Smartphoton-JK-BMS / ©JLM 2025-2026",
            model: payload.BMS_A || "JK-BMS - RS485 - Ip Gateway",
            sw_version: "3.5"
        }
    };

    if (entityType === "switch") {
        configPayload.payload_on = "True";
        configPayload.payload_off = "False";
        configPayload.state_on = "True";
        configPayload.state_off = "False";
        configPayload.icon = "mdi:toggle-switch";
    } else {
        configPayload.mode = "box";
        const meta = inferMeta(key);
        if (meta.unit !== undefined) configPayload.unit_of_measurement = meta.unit;
        if (meta.min !== undefined) configPayload.min = meta.min;
        if (meta.max !== undefined) configPayload.max = meta.max;
        if (meta.step !== undefined) configPayload.step = meta.step;
    }

    const configTopic = `${discoveryPrefix}/${entityType}/${deviceID}/${configPayload.object_id}/config`;

    return {
        topic: configTopic,
        payload: JSON.stringify(configPayload),
        retain: true
    };
}

function createStateMessage(key, value) {
    const cleanKey = key === "Device_address_N" ? "bms_device_address" : key.replace(/_[A-Z]+$/, "").toLowerCase();
    return {
        topic: `${baseTopic}/control/${cleanKey}/state`,
        payload: formatBoolean(value),
        retain: true
    };
}

// -----------------------------------------------------------------
// 4) Construction des messages
// -----------------------------------------------------------------
let outMsgs = [];
let hasChanges = false;
let keys = Object.keys(payload).sort();

for (const key of keys) {
    const currentNormalized = normalizeValue(payload[key]);
    const previousNormalized = normalizeValue(lastSetup[key]);

    const keyWasKnown = Object.prototype.hasOwnProperty.call(lastSetup, key);
    const changed = !setupAlreadySent || forceRepublish || !keyWasKnown || currentNormalized !== previousNormalized;

    // Recréation config :
    // - au premier envoi
    // - en republish forcé
    // - si une nouvelle clé apparaît
    if (!setupAlreadySent || forceRepublish || !keyWasKnown) {
        outMsgs.push(createConfigPayload(key));
    }

    // Publication d'état :
    // - au premier envoi
    // - en republish forcé
    // - si changement
    if (changed) {
        outMsgs.push(createStateMessage(key, payload[key]));
        lastSetup[key] = payload[key];
        hasChanges = true;
    }
}

// -----------------------------------------------------------------
// 5) Sauvegarde état / logs
// -----------------------------------------------------------------
if (!setupAlreadySent || forceRepublish || hasChanges) {
    flow.set(setupSentKey, true);
    flow.set(lastSetupKey, lastSetup);

    // On nettoie les flags de forçage une fois utilisés
    flow.set(forceKeyFlow, false);
    flow.set(forceAllKeyFlow, false);

    if (!setupAlreadySent) {
        node.warn(`✓ Setup INITIAL envoyé pour BMS ${slaveIdStr} (${outMsgs.length} messages)`);
    } else if (forceRepublish) {
        node.warn(`↻ Setup FORCÉ renvoyé pour BMS ${slaveIdStr} (${outMsgs.length} messages)`);
    } else {
        node.warn(`✓ Setup CHANGEMENTS détectés pour BMS ${slaveIdStr} (${outMsgs.length} messages)`);
    }

    return [outMsgs];
} else {
    node.debug(`⊘ Setup: aucun changement pour BMS ${slaveIdStr}`);
    return null;
}

// Vérifie que le payload est un Buffer
if (Buffer.isBuffer(msg.payload)) {
    // Convertit chaque octet en hexadécimal sur 2 chiffres
    msg.payload = msg.payload
        .toString('hex')                // Convertit tout le buffer en une chaîne hexadécimale continue
        .match(/.{1,2}/g)               // Coupe la chaîne tous les 2 caractères
        .join(' ') + '\n';              // Ajoute un espace entre chaque octet et un retour à la ligne
} else if (Array.isArray(msg.payload)) {
    // Si c'est un tableau, on le traite aussi
    msg.payload = msg.payload
        .map(x => x.toString(16).padStart(2, '0'))
        .join(' ') + '\n';
} else {
    // Sinon, on ne fait rien ou on peut lever une erreur
    msg.payload = 'Payload non reconnu\n';
}
return msg;

// Traitement des trames déjà extraites par le Framer Broadcast RS485
// Ce noeud NE reconstruit plus les trames
// Il reçoit des objets du type :
// {
//   topic: "broadcast/jkbms_reply" | "broadcast/modbus_poll",
//   payload: <Buffer>,
//   hex: "...",
//   slave: 2
// }

function normalizeToBuffer(value) {
    if (Buffer.isBuffer(value)) {
        return value;
    }
    if (value && value.type === "Buffer" && Array.isArray(value.data)) {
        return Buffer.from(value.data);
    }
    if (Array.isArray(value)) {
        return Buffer.from(value);
    }
    return null;
}

function normalizeBmsIdentifier(v) {
    if (v === null || v === undefined) return null;
    if (typeof v === "string") {
        const t = v.trim().toLowerCase();
        if (!t) return null;
        if (t === "master") return "master";
        const n = Number(t);
        if (Number.isFinite(n)) return n === 0 ? "master" : String(n);
        return t;
    }
    if (typeof v === "number") {
        if (!Number.isFinite(v)) return null;
        return v === 0 ? "master" : String(v);
    }
    return null;
}

function refreshDetectedBms(id) {
    if (!id) return;
    const now = Date.now();
    const WINDOW_MS = 120 * 1000;
    let diag = flow.get("diag_serial_stats") || {};
    let seen = diag.detected_bms_seen || {};

    seen[id] = now;

    for (const [k, ts] of Object.entries(seen)) {
        if ((now - ts) > WINDOW_MS) {
            delete seen[k];
        }
    }

    const list = Object.keys(seen).sort((a, b) => {
        if (a === "master") return -1;
        if (b === "master") return 1;
        const na = Number(a), nb = Number(b);
        if (Number.isFinite(na) && Number.isFinite(nb)) return na - nb;
        return String(a).localeCompare(String(b));
    });

    diag.detected_bms_seen = seen;
    diag.detected_bms = list.length;
    diag.detected_bms_list = list.join(", ");
    flow.set("diag_serial_stats", diag);
}

const pendingDataKey = 'jkbms_pending_data';
let pendingData = context.get(pendingDataKey) || null;

// Si le contexte a restauré un objet sérialisé, normaliser le payload
if (pendingData && pendingData.payload) {
    const normalizedPending = normalizeToBuffer(pendingData.payload);
    if (normalizedPending) {
        pendingData.payload = normalizedPending;
    } else {
        pendingData = null;
        context.set(pendingDataKey, null);
    }
}

// Le Framer met son objet dans msg.payload
const framed = msg.payload;

if (!framed || typeof framed !== "object" || !framed.topic || !framed.payload) {
    return null;
}

const frame = normalizeToBuffer(framed.payload);

if (!frame) {
    return null;
}

function typeTrame(byte) {
    if (byte === 1) return "setup";
    if (byte === 2) return "data";
    return "autre";
}

let outputFrames = [];

// --------------------------------------------------
// 1) Requête Modbus courte
// --------------------------------------------------
if (framed.topic === "broadcast/modbus_poll") {
    let reqMsg = {
        payload: Buffer.from(frame),
        bms_adresse: frame[0],
        bms_type: "requete",
        _frameSource: "REQUETE",
        _frameLength: frame.length,
        _hex: framed.hex || frame.toString("hex")
    };

    return reqMsg;
}

// --------------------------------------------------
// 2) Réponse JK-BMS
// --------------------------------------------------
if (framed.topic === "broadcast/jkbms_reply") {
    // Vérification minimale header
    if (
        frame.length < 6 ||
        frame[0] !== 0x55 ||
        frame[1] !== 0xAA ||
        frame[2] !== 0xEB ||
        frame[3] !== 0x90
    ) {
        return null;
    }

    const frameType = typeTrame(frame[4]);

    if (frameType === "data") {
        // On mémorise la data, en attente de la setup suivante
        pendingData = {
            payload: Buffer.from(frame),
            bms_adresse: framed.slave !== undefined ? framed.slave : "master",
            bms_type: "data",
            _frameSource: "JK-BMS",
            _frameLength: frame.length,
            _hex: framed.hex || frame.toString("hex")
        };

        context.set(pendingDataKey, pendingData);
        return null;
    }

    if (frameType === "setup") {
        // Extraction du numéro pack à offset 270..273
        // seulement si la trame est assez longue
        let bmsNumber = null;

        if (frame.length > 273) {
            bmsNumber =
                frame[270] |
                (frame[271] << 8) |
                (frame[272] << 16) |
                (frame[273] << 24);
        }

        const normalizedId = normalizeBmsIdentifier(bmsNumber);
        if (normalizedId) {
            refreshDetectedBms(normalizedId);
        }

        // Envoyer d'abord la DATA mémorisée avec le bon numéro
        if (pendingData) {
            pendingData.bms_numero = bmsNumber;
            outputFrames.push(pendingData);
            pendingData = null;
            context.set(pendingDataKey, null);
        }

        // Puis envoyer la SETUP
        let setupMsg = {
            payload: Buffer.from(frame),
            bms_adresse: framed.slave !== undefined ? framed.slave : "master",
            bms_type: "setup",
            bms_numero: bmsNumber,
            _frameSource: "JK-BMS",
            _frameLength: frame.length,
            _hex: framed.hex || frame.toString("hex")
        };

        outputFrames.push(setupMsg);

        if (outputFrames.length === 1) {
            return outputFrames[0];
        }
        return [outputFrames];
    }

    return null;
}

return null;

// Récupère le nombre total de JKBMS
let nb = Number(global.get("nb_jkbms")) || 1;
nb = Math.max(1, nb);

// -------------------------
// RESET DATA MASTER
// -------------------------
flow.set("discoverySent_BMS_master", false);
flow.set("discoveredKeys_BMS_master", []);

// -------------------------
// RESET ALARMES MASTER
// -------------------------
flow.set("discoverySent_ALARMS_BMS_master", false);
flow.set("lastAlarmState_BMS_master", null);

// -------------------------
// RESET BMS ESCLAVES
// -------------------------
for (let i = 1; i <= nb; i++) {
    // DATA
    flow.set(`discoverySent_BMS_${i}`, false);
    flow.set(`discoveredKeys_BMS_${i}`, []);

    // ALARMES
    flow.set(`discoverySent_ALARMS_BMS_${i}`, false);
    flow.set(`lastAlarmState_BMS_${i}`, null);
}

// -------------------------
// RESET GLOBAL
// -------------------------
flow.set("discoverySent_GLOBAL_ALARM", false);
flow.set("lastGlobalAlarmState", null);

node.warn(`Discovery reset done for DATA + ALARMS + GLOBAL on Master + ${nb} BMS.`);
return msg;

var BMS = msg.payload["Device_address_N"];
// Pour debug, affichons la valeur BMS
node.warn(`BMS Nb:${BMS} is alive`);
return msg;

const errorList = [
    "Balancing resistance too high",               // bit 0
    "MOS over-temperature protection",             // bit 1
    "Number of cells does not match parameter",    // bit 2
    "Abnormal current sensor",                     // bit 3
    "Cell over-voltage protection",                // bit 4
    "Battery over-voltage protection",             // bit 5
    "Overcurrent charge protection",               // bit 6
    "Charge short-circuit protection",             // bit 7
    "Over-temperature charge protection",          // bit 8
    "Low temperature charge protection",           // bit 9
    "Internal communication anomaly",              // bit 10
    "Cell under-voltage protection",               // bit 11
    "Battery under-voltage protection",            // bit 12
    "Overcurrent discharge protection",            // bit 13
    "Discharge short-circuit protection",          // bit 14
    "Over-temperature discharge protection",       // bit 15
    "Charge MOS anomaly",                          // bit 16
    "Discharge MOS anomaly",                       // bit 17
    "GPS disconnected",                            // bit 18
    "Please modify the authorization password in time", // bit 19
    "Discharge activation failure",                // bit 20
    "Battery over-temperature alarm",              // bit 21
    "Temperature sensor anomaly",                  // bit 22
    "Parallel module anomaly",                     // bit 23
    "Erreur fictive Bit 24",
    "Erreur fictive Bit 25",
    "Erreur fictive Bit 26",
    "Erreur fictive Bit 27",
    "Erreur fictive Bit 28",
    "Erreur fictive Bit 29",
    "Erreur fictive Bit 30",
    "Erreur fictive Bit 31"
];

const buffer = msg.payload;
if (buffer.length <= 169) {
    msg.payload = { error: "Buffer too small to extract error code", bms_address: msg.bms_adresse };
    return msg;
}

// Swap bytes as requested
const swappedErrorCode =
    (buffer[169] << 24) |
    (buffer[168] << 16) |
    (buffer[167] << 8) |
    (buffer[166]);

const activeErrors = [];
for (let i = 0; i < errorList.length; i++) {
    if (swappedErrorCode & (1 << i)) {
        activeErrors.push(errorList[i]);
    }
}

// Construction du payload dans le format "référence"
// MODIFICATION: Ne pas inclure le préfixe "🚨 BMS Alarm Alert" dans le tableau errors
msg.payload = {
    bms_address: msg.bms_numero,
    error_code: swappedErrorCode,
    errors: activeErrors.length > 0 ? activeErrors : []
};

return msg;

