// Diag Serial Snapshot
// Déclenché toutes les 30 secondes par un inject

const now = Date.now();
const WINDOW_MS = 120 * 1000;

let s = flow.get("diag_serial_stats") || {
    first_ts: now,
    last_serial_rx_ts: 0,
    buffers_30s: 0,
    bytes_30s: 0,
    short_buffers_30s: 0,
    multi_header_buffers_30s: 0,
    frame_candidates_30s: 0,
    frames_emitted_30s: 0,
    emitted_frame_bytes_30s: 0,
    last_len: 0,
    sum_len_30s: 0,
    max_len_30s: 0,
    transport: "unknown",
    detected_bms_seen: {},
    detected_bms: 0,
    detected_bms_list: ""
};

let seen = s.detected_bms_seen || {};
for (const [id, ts] of Object.entries(seen)) {
    if ((now - ts) > WINDOW_MS) {
        delete seen[id];
    }
}

const detectedList = Object.keys(seen).sort((a, b) => {
    if (a === "master") return -1;
    if (b === "master") return 1;
    const na = Number(a), nb = Number(b);
    if (Number.isFinite(na) && Number.isFinite(nb)) return na - nb;
    return String(a).localeCompare(String(b));
});

s.detected_bms_seen = seen;
s.detected_bms = detectedList.length;
s.detected_bms_list = detectedList.join(", ");

const serialAge = s.last_serial_rx_ts ? Number(((now - s.last_serial_rx_ts) / 1000).toFixed(3)) : null;
const avgLen = s.buffers_30s ? Math.round(s.sum_len_30s / s.buffers_30s) : 0;
const bytesPerBufferAvg = avgLen;
const framesEmitted = s.frames_emitted_30s || 0;
