let lastModbusSlave = flow.get("last_modbus_slave_broadcast");

// --------------------------------------------------
// CRC16 Modbus
// --------------------------------------------------
function modbusCRC(buffer, start, length) {
    let crc = 0xFFFF;
    for (let i = start; i < start + length; i++) {
        crc ^= buffer[i];
        for (let j = 0; j < 8; j++) {
            if (crc & 0x0001) {
                crc = (crc >> 1) ^ 0xA001;
            } else {
                crc >>= 1;
            }
        }
    }
    return crc & 0xFFFF;
}

// --------------------------------------------------
// Poll Modbus stricte
// [addr][10][16][20|1e][00][01][02][00][00][crcLo][crcHi]
// --------------------------------------------------
function isModbusPollStrict(buffer, pos) {
    if (buffer.length - pos < 11) return false;

    const addr = buffer[pos];
    const func = buffer[pos + 1];
    const regH = buffer[pos + 2];
    const regL = buffer[pos + 3];
    const qtyH = buffer[pos + 4];
    const qtyL = buffer[pos + 5];
    const byteCount = buffer[pos + 6];
    const dataH = buffer[pos + 7];
    const dataL = buffer[pos + 8];
    const crcLo = buffer[pos + 9];
    const crcHi = buffer[pos + 10];

    if (!(addr >= 1 && addr <= 15)) return false;
    if (func !== 0x10) return false;
    if (regH !== 0x16) return false;
    if (!(regL === 0x20 || regL === 0x1e)) return false;
    if (qtyH !== 0x00 || qtyL !== 0x01) return false;
    if (byteCount !== 0x02) return false;
    if (dataH !== 0x00 || dataL !== 0x00) return false;

    const crc = modbusCRC(buffer, pos, 9);
    return (crcLo === (crc & 0xFF)) && (crcHi === ((crc >> 8) & 0xFF));
}

// --------------------------------------------------
// Header JK-BMS
// --------------------------------------------------
function isJKHeader(buffer, pos) {
    return (
        buffer.length - pos >= 4 &&
        buffer[pos] === 0x55 &&
        buffer[pos + 1] === 0xAA &&
        buffer[pos + 2] === 0xEB &&
        buffer[pos + 3] === 0x90
    );
}

const MIN_JK_REPLY = 180;
const MAX_BUFFER = 16384;

let i = 0;

while (i < buf.length) {

    // 1) Poll Modbus valide
    if (isModbusPollStrict(buf, i)) {
        const frame = buf.slice(i, i + 11);
        const slave = frame[0];
        lastModbusSlave = slave;
        flow.set("last_modbus_slave_broadcast", slave);

        frames.push({
            topic: "broadcast/modbus_poll",
            payload: frame,
            hex: frame.toString("hex"),
            slave,
            reg: (frame[2] << 8) | frame[3]
        });

        i += 11;
        continue;
    }

    // 2) Reply JK-BMS
    if (isJKHeader(buf, i)) {
        let next = -1;

        for (let j = i + 4; j < buf.length; j++) {
            if (isJKHeader(buf, j) || isModbusPollStrict(buf, j)) {
                next = j;
                break;
            }
        }

        // pas encore de fin trouvée -> attendre plus de données
        if (next === -1) {
            break;
        }

        const frame = buf.slice(i, next);

        if (frame.length >= MIN_JK_REPLY) {
            frames.push({
                topic: "broadcast/jkbms_reply",
                payload: frame,
                hex: frame.toString("hex"),
                slave: lastModbusSlave
            });
            i = next;
            continue;
        } else {
            // faux header ou fragment trop court
            i += 1;
            continue;
        }
    }

    i++;
}

