        `${discoveryPrefix}/number/${deviceID}/bms_bms_device_address/config`,
        `${discoveryPrefix}/number/${deviceID}_bms_bms_device_address/config`,
        `${discoveryPrefix}/number/${deviceID}/Device_address_N/config`,
        `${discoveryPrefix}/number/${deviceID}/Device_address/config`
    ];

    for (const topic of oldTopics) {
        msgs.push({
            topic,
            payload: "",
            retain: true
        });
    }

    return msgs;
}

function buildDiscoveryMessages(payloadObj) {
    const msgs = [];

    if (payloadObj.Device_address_N !== undefined) {
