        let cfg = {
            name: key === "Device_address_N"
                ? "BMS device address"
                : key.replace(/_[A-Z]+$/, "").replace(/_/g, " "),
            unique_id: `${deviceID}_bms_${cleanKey}_v4`,
            object_id: `${baseTopic.toLowerCase()}_bms_${cleanKey}`,
            state_topic: `${baseTopic}/control/${cleanKey}/state`,
