            entity_category: "config",
            device: {
                identifiers: [deviceID],
                name: deviceName,
                manufacturer: "Smartphoton-JK-BMS / ©JLM 2025-2026",
                model: "Setup BMS",
                sw_version: "3.5"
            }
        };

        // IMPORTANT :
        // Force l'entity_id HA exact :
        // number.bms_1_bms_device_address
        // number.bms_2_bms_device_address
        if (key === "Device_address_N") {
            cfg.name = "BMS device address";
            cfg.unique_id = `${deviceID}_bms_device_address_v4`;
            cfg.object_id = `${baseTopic.toLowerCase()}_bms_device_address`;
            cfg.default_entity_id = `number.${baseTopic.toLowerCase()}_bms_device_address`;
            cfg.state_topic = `${baseTopic}/control/bms_device_address/state`;
            cfg.command_topic = `${baseTopic}/control/bms_device_address/set`;
        }

        if (entityType === "number") {
            cfg.mode = "box";

            const bounds = customBounds[key];

            if (bounds) {
                cfg.min = bounds.min;
                cfg.max = bounds.max;
                cfg.step = bounds.step;
                if (bounds.unit) cfg.unit_of_measurement = bounds.unit;
            } else {
                if (key.endsWith("_V")) {
                    cfg.unit_of_measurement = "V";
                    cfg.min = 0;
                    cfg.max = 5;
                    cfg.step = 0.01;
                } else if (key.endsWith("_A")) {
                    cfg.unit_of_measurement = "A";
                    cfg.min = 0;
                    cfg.max = 400;
                    cfg.step = 0.1;
                } else if (key.endsWith("_S")) {
