    node.error("Réponse alarmes invalide");
    return null;
}

// IMPORTANT : l'adresse réelle du BMS est dans la réponse Modbus
const slaveId = Number(msg.payload[0]);

if (!Number.isFinite(slaveId) || slaveId <= 0) {
    node.error("Adresse BMS invalide dans la réponse alarme");
    return null;
}

const byteCount = msg.payload[2];

if (byteCount !== 4) {
    node.error(`Nombre d'octets alarmes incorrect: ${byteCount}, attendu: 4`);
    return null;
}

const alarmValue = msg.payload.readUInt32BE(3);

const activeAlarms = [];
const alarmDetails = {};
const alarmBits = [];

for (let bit = 0; bit <= 23; bit++) {
    if (alarmValue & (1 << bit)) {
        const description = ALARM_BITS[bit] || `Unknown alarm bit ${bit}`;
        activeAlarms.push({ bit, description });
        alarmDetails[`BIT${bit}`] = description;
        alarmBits.push(bit);
    }
}

alarmDetails.status = activeAlarms.length === 0
    ? "No BMS alarms"
    : "🚨 BMS Alarm Alert";

msg.alarms = {
    bms_id: slaveId,
    timestamp: new Date().toISOString(),
    slave_id: slaveId,
    raw_value: alarmValue,
    raw_hex: "0x" + alarmValue.toString(16).toUpperCase().padStart(8, "0"),
    raw_binary: alarmValue.toString(2).padStart(24, "0"),
    alarm_count: activeAlarms.length,
    has_alarms: activeAlarms.length > 0,
    active_bits: alarmBits,
    active_alarms: activeAlarms,
    alarm_details: alarmDetails
};

msg.payload = {
    bms_id: slaveId,
    status: activeAlarms.length > 0 ? "ALARM" : "OK",
    count: activeAlarms.length,
    alarms: activeAlarms.map(a => a.description),
    bits: alarmBits,
    timestamp: new Date().toISOString()
};

