function buildDiscoveryMessages(payloadObj) {
    const msgs = [];
    for (const key in payloadObj) {
        const cleanKey = key.replace(/_[A-Z]+$/, "").toLowerCase();
        const sensorTopic = `${baseTopic}/state/${cleanKey}`;

        // Vérifier si c'est un champ "number" (configuration)
        if (numberFields.includes(key)) {
            const commandTopic = `${baseTopic}/control/${cleanKey}/set`;

            // Définir la plage selon le champ
            let min = 0;
            let max = 100;
            let unit = "%";
            let step = 1;
            let icon = "mdi:tune";

            if (key === "LCD_buzzer_trigger_N") {
                max = 25;
                unit = "";
                icon = "mdi:volume-high";
            } else if (key === "Request_Charge_voltage_Time_H" || key === "Request_Float_voltage_Time_H") {
                min = 0;
                max = 25;
                step = 0.1;
                unit = "h";
                icon = "mdi:timer-outline";
            }

            let cfg = {
                name: `BMS ${key.replace(/_[A-Z]+$/, "").replace(/_/g, " ")}`,
                unique_id: `${deviceID}_static_bms_${cleanKey}_v4`,
                state_topic: sensorTopic,
                command_topic: commandTopic,
                min: min,
                max: max,
                step: step,
                mode: "box",
                entity_category: "config",
                enabled_by_default: true,
                icon: icon,
                device: {
                    identifiers: [deviceID],
                    name: deviceName,
                    manufacturer: "Smartphoton-JK-BMS / ©JLM 2025-2026",
                    model: payloadObj.BMS_A || "rs485 vers MQTT",
                    sw_version: payloadObj.SW_N || "3.5"
                }
            };

            // Ajouter l'unité seulement si elle existe
            if (unit) {
                cfg.unit_of_measurement = unit;
            }

            // Force l'entity_id HA stable pour les number statics
            cfg.object_id = `${baseTopic.toLowerCase()}_bms_${cleanKey}`;
            cfg.default_entity_id = `number.${cfg.object_id}`;

            msgs.push({
                topic: `${discoveryPrefix}/number/${cfg.object_id}/config`,
                payload: JSON.stringify(cfg),
                retain: true
            });
        } else {
            // Capteur classique (sensor)
            let cfg = {
                name: `BMS ${key.replace(/_[A-Z]+$/, "").replace(/_/g, " ")}`,
                unique_id: `${deviceID}_static_bms_${cleanKey}_v4`,
                state_topic: sensorTopic,
                enabled_by_default: true,
                // \u274c SUPPRESSION de "entity_category: diagnostic"
                device: {
                    identifiers: [deviceID],
                    name: deviceName,
                    manufacturer: "Smartphoton-JK-BMS / ©JLM 2025",
                    model: payloadObj.BMS_A || "rs485 vers MQTT",
                    sw_version: payloadObj.SW_N || "3.3"
                }
            };

            // unités & classes
            if (key.endsWith("_S")) {
                cfg.unit_of_measurement = "s";
                cfg.device_class = "duration";
                cfg.state_class = "measurement";
            } else if (key.endsWith("_H")) {
                cfg.unit_of_measurement = "h";
                cfg.device_class = "duration";
                cfg.state_class = "measurement";
            } else if (key.endsWith("_N") && key.includes("Time")) {
                cfg.unit_of_measurement = "s";
                cfg.device_class = "duration";
                cfg.state_class = "measurement";
            } else if (key.endsWith("_N") && !key.includes("Serial")) {
                cfg.state_class = "measurement";
            }

            // icônes
            if (key.includes("Password")) cfg.icon = "mdi:form-textbox-password";
            else if (key.includes("Serial")) cfg.icon = "mdi:barcode";
            else if (key.includes("protocol")) cfg.icon = "mdi:protocol";
            else if (key.includes("version") || key.includes("SW") || key.includes("FW"))
                cfg.icon = "mdi:numeric-10";
            else if (key.includes("Uptime")) {
                cfg.icon = "mdi:timer-outline";
                cfg.device_class = "duration";
            } else if (key.includes("date")) cfg.icon = "mdi:calendar";

            // Force l'entity_id HA stable pour les sensor statics
            cfg.object_id = `${baseTopic.toLowerCase()}_bms_${cleanKey}`;
            cfg.default_entity_id = `sensor.${cfg.object_id}`;

            msgs.push({
                topic: `${discoveryPrefix}/sensor/${cfg.object_id}/config`,
                payload: JSON.stringify(cfg),
                retain: true
            });
        }
    }
    return msgs;
}

function buildStateMessages(payloadObj) {
    const msgs = [];
    for (const key in payloadObj) {
        const cleanKey = key.replace(/_[A-Z]+$/, "").toLowerCase();
        msgs.push({
            topic: `${baseTopic}/state/${cleanKey}`,
            payload: formatValue(payloadObj[key]),
            retain: true
        });
    }
    return msgs;
}

