// 4. Construction des messages
const payload = msg.payload;

var outputMsgs = [];

// Envoyer les messages de discovery seulement si pas déjà fait
if (!discoveryAlreadySent) {
    outputMsgs = buildDiscoveryMessages(payload);
    flow.set(discoveryKey, true);
}

// Ajouter les messages de state
const stateMsgs = buildStateMessages(payload);
outputMsgs = outputMsgs.concat(stateMsgs);

return [outputMsgs];

let currentAddress = global.get("slaveAddress-Trame1") || 1; // Valeur par défaut : 1
let Number_of_BMS = global.get("nb_jkbms") || 1; // Valeur par défaut : 1

// Incrémenter l'adresse, revenir à 1 après 8
currentAddress = currentAddress >= Number_of_BMS ? 1 : currentAddress + 1;

global.set("slaveAddress-Trame1", currentAddress);

//node.warn(`Prochaine adresse esclave Trame1 : ${currentAddress}`);
msg.payload = currentAddress;
return msg; // Continuer vers le prochain nœud

let currentAddress = global.get("slaveAddress-Trame3") || 1; // Valeur par défaut : 1
let Number_of_BMS = global.get("nb_jkbms") || 1; // Valeur par défaut : 1

// Incrémenter l'adresse, revenir à 1 après 8
currentAddress = currentAddress >= Number_of_BMS ? 1 : currentAddress + 1;

global.set("slaveAddress-Trame3", currentAddress);

// node.warn(`Prochaine adresse esclave Trame3 : ${currentAddress}`);
msg.payload = currentAddress;
return msg; // Continuer vers le prochain nœud

// ========== LECTURE DES ALARMES JK-BMS ==========
// Lecture registre 0x12A0 - alarmes UINT32
// Corrigé : boucle dédiée sur tous les BMS pour créer les alarmes BMS 1/2/3/...

const totalBms = Number(global.get("nb_jkbms")) || 1;

let slaveId = Number(global.get("slaveAddress-Trame4")) || 1;
if (slaveId < 1 || slaveId > totalBms) slaveId = 1;

// Prépare déjà le prochain BMS pour le prochain passage
let nextSlaveId = slaveId >= totalBms ? 1 : slaveId + 1;
global.set("slaveAddress-Trame4", nextSlaveId);

const functionCode = 0x03;
const address = 0x12A0;

function crc16(buffer) {
    let crc = 0xFFFF;
    for (let i = 0; i < buffer.length; i++) {
        crc ^= buffer[i];
        for (let j = 0; j < 8; j++) {
            crc = (crc & 1) ? (crc >> 1) ^ 0xA001 : crc >> 1;
        }
    }
    return crc;
}

const dataBuffer = Buffer.from([
    slaveId,
    functionCode,
    (address >> 8) & 0xFF,
    address & 0xFF,
    0x00,
    0x02
]);

const crc = crc16(dataBuffer);
const finalBuffer = Buffer.allocUnsafe(dataBuffer.length + 2);
dataBuffer.copy(finalBuffer);
finalBuffer.writeUInt16LE(crc, dataBuffer.length);

msg.topic = "Trame-Alarmes-BMS";
msg.payload = finalBuffer;

msg.bmsId = slaveId;
msg.bms_id = slaveId;
msg.bms_numero = slaveId;

flow.set("last_alarm_request_bms", slaveId);

return msg;

let interval = Number(global.get("non_broadcasting_data_interval_s"));

if (!isFinite(interval)) interval = 1;
if (interval < 1) interval = 1;
if (interval > 30) interval = 30;

const immediate = { ...msg };
delete immediate.delay;

const nextTick = {
    payload: msg.payload,
    host: msg.host,
    port: msg.port,
    delay: Math.round(interval * 1000) // ms
};

return [immediate, nextTick];

let p = msg.payload || {};

let cellCount = Number(p.cell_count_N);
if (!Number.isFinite(cellCount) || cellCount < 1) {
    cellCount = 16;
}

// Borné à 16 car le parser actuel de la trame 3 va jusqu'à Cell_16_volt_V
cellCount = Math.min(cellCount, 16);

global.set("jk_cell_count", cellCount);
msg.cell_count_N = cellCount;

return msg;

let slot = flow.get('gateway_tcp_slot') || 'A';
if (slot !== 'B') slot = 'A';
node.status({fill:'blue',shape:'dot',text:'slot ' + slot});
return slot === 'A' ? [msg, null] : [null, msg];

flow.set('lastDataTs_master', 0);
flow.set('gateway_status_master', 'unknown');
flow.set('gateway_tcp_slot', 'A');
flow.set('failoverTs_master', 0);
node.status({fill:'grey',shape:'ring',text:'slot A'});
return null;

const slot = flow.get('gateway_tcp_slot') || 'A';
flow.set('lastDataTs_master', Date.now());
flow.set('gateway_status_master', slot === 'A' ? 'online' : 'online_B');
flow.set('failoverTs_master', 0);
flow.set('failoverCount_master', 0); // ← reset compteur dès données reçues
return null;

const TIMEOUT_MS   = 120000;
const MAX_FAILOVER = 4; // 2 allers-retours max

if (global.get('use_gateway') !== true) return null;

// Abandon si gateway déclarée injoignable
if (flow.get('gateway_status_master') === 'unreachable') return null;

const last       = flow.get('lastDataTs_master') || 0;
const failoverTs = flow.get('failoverTs_master') || 0;

if (last === 0 && failoverTs === 0) return null;

const ref     = last > 0 ? last : failoverTs;
const elapsed = Date.now() - ref;

if (elapsed <= TIMEOUT_MS) return null;

const count   = (flow.get('failoverCount_master') || 0) + 1;
const current = flow.get('gateway_tcp_slot') || 'A';
const next    = current === 'A' ? 'B' : 'A';

if (count >= MAX_FAILOVER) {
    flow.set('gateway_status_master', 'unreachable');
    flow.set('failoverCount_master', count);
    node.warn(`Gateway master: aucune réponse après ${count} basculements → abandon`);
    return [{ payload: { status: 'unreachable', attempts: count } }];
}

flow.set('gateway_tcp_slot', next);
flow.set('gateway_status_master', 'failover');
flow.set('lastDataTs_master', 0);
flow.set('failoverTs_master', Date.now());
flow.set('failoverCount_master', count);

node.warn(`Gateway watchdog: timeout ${Math.round(elapsed/1000)}s -> failover ${current} => ${next} (tentative ${count}/${MAX_FAILOVER})`);
return [{ payload: { status: 'failover', from: current, to: next, elapsed_s: Math.round(elapsed/1000), attempt: count } }];

// Node-RED function node pour générer la trame Modbus d'écriture
// Entrée attendue: msg.payload contient la tension (ex: 3.42)
function generateModbusWriteCommand(voltage) {
    // Fonction de calcul CRC16 Modbus
    function crc16(buffer) {
        let crc = 0xFFFF;
        for (let i = 0; i < buffer.length; i++) {
            crc ^= buffer[i];
            for (let j = 0; j < 8; j++) {
                if (crc & 0x0001) {
                    crc = (crc >> 1) ^ 0xA001;
                } else {
                    crc = crc >> 1;
                }
            }
        }
        return crc;
    }

    // Conversion de la tension en valeur entière (échelle 1/1000)
    const voltageValue = Math.round(voltage * 1000);

    // Construction de la trame sans CRC
    // Récupération de l'adresse esclave depuis le contexte global
    const slaveId = global.get("slaveAddress-setup") || 0x01; // Valeur par défaut si non définie

    const command = [
        slaveId,                           // Slave ID
        0x10,                           // Function code (16/0x10 - Write Multiple Registers)
        0x10,                           // Register address high byte (0x10)
        0x84,                           // Register address low byte (0x84)
        0x00,                           // Quantity high byte (2 registres pour uint32)
        0x02,                           // Quantity low byte (2 registres pour uint32)
        0x04,                           // Byte count (4 bytes pour uint32)
        (voltageValue >> 24) & 0xFF,    // Valeur MSB (premier octet)
        (voltageValue >> 16) & 0xFF,    // Deuxième octet
        (voltageValue >> 8) & 0xFF,     // Troisième octet
        voltageValue & 0xFF             // Valeur LSB (dernier octet)
    ];

    // Calcul du CRC
    const crc = crc16(Buffer.from(command));

    // Ajout du CRC à la trame (en ordre inverse car little-endian)
    command.push(crc & 0xFF);          // CRC low byte
    command.push((crc >> 8) & 0xFF);   // CRC high byte

    return Buffer.from(command);
}

// Extraction de la valeur de tension et envoi de la trame
const tensionAEcrire = parseFloat(msg.payload);

