const inputEnv = msg.payload.toString().trim();

let configPath;
let statusColor;
let bip;

switch(inputEnv) {
    case 'HAOS':
        configPath = '/data/options.json';
        msg.environment = 'Home Assistant OS';
        bip = 1;
        statusColor = 'green';
        break;
    case 'Docker':
        configPath = '/data/options.json';
        msg.environment = 'Docker (autre)';
        bip = 2;
        statusColor = 'blue';
        break;
    case 'Linux':
        configPath = '/data/options.json';
        msg.environment = 'Linux barebone';
        bip = 3;
        statusColor = 'yellow';
        break;
    case 'Windows':
        configPath = 'C:\\data\\options.json';
        msg.environment = 'Windows';
        bip = 4;
        statusColor = 'purple';
        break;
    default:
        configPath = './data/options.json';
        msg.environment = 'Inconnu';
        bip = 5;
        statusColor = 'red';
}

// 2ème digit : premium actif ou non
const premium = global.get('premium') || {};
const premiumDigit = (premium.status === 'active') ? '1' : '0';

msg.filename = configPath;
msg.payload = { "bip": String(bip) + premiumDigit };  // ex: "11", "10", "21"...
msg.headers = { "Content-Type": "application/json" };
node.status({fill: statusColor, shape: "dot", text: msg.environment});
return msg;

// Récupérer l'adresse du BMS depuis la variable globale
const bmsAddress = global.get('slaveAddress-Trame3') || 'BMS-Unknown';

// Extraire le nombre de cellules depuis payload.cell_count_N
const cellCount = msg.payload.cell_count_N || 16;

// Extraire les données de tension des cellules - DYNAMIQUE
const cellVoltages = [];
for (let i = 1; i <= cellCount; i++) {
    const key = `Cell_${i}_volt_V`;
    if (msg.payload[key] !== undefined) {
        cellVoltages.push({
            cell: i,
            voltage: parseFloat(msg.payload[key]).toFixed(3)
        });
    }
}

// Calculer min, max et moyenne des tensions
const voltages = cellVoltages.length > 0 ? cellVoltages.map(c => parseFloat(c.voltage)) : [0];
const minVoltage = Math.min(...voltages);
const maxVoltage = Math.max(...voltages);
const avgVoltage = cellVoltages.length > 0 ? (voltages.reduce((a, b) => a + b, 0) / voltages.length).toFixed(3) : 0;
const voltageBalance = (maxVoltage - minVoltage).toFixed(3);

// Extraire les données de température
const temperatures = [
    { name: 'MOS', value: msg.payload.Mos_temp_T },
    { name: 'Sonde 1', value: msg.payload.Sonde_1_temp_T },
    { name: 'Sonde 2', value: msg.payload.Sonde_2_temp_T },
    { name: 'Sonde 3', value: msg.payload.Sonde_3_temp_T },
    { name: 'Sonde 4', value: msg.payload.Sonde_4_temp_T }
].filter(t => t.value !== undefined);

const maxTemp = temperatures.length > 0 ? Math.max(...temperatures.map(t => t.value)) : 0;
const minTemp = temperatures.length > 0 ? Math.min(...temperatures.map(t => t.value)) : 0;

// Construire l'objet formaté pour le dashboard
const formattedData = {
    bmsAddress: bmsAddress,
    timestamp: new Date().toISOString(),
    cellCount: cellCount,

    // Tension globale
    tensionTotale: {
        value: msg.payload.Tension_Totale_volt_V || 0,
        unit: 'V'
    },

    // Courant
    courantTotal: {
        value: msg.payload.Courant_total_A || 0,
        unit: 'A'
    },

    // Puissance
    puissance: {
        value: msg.payload.Puissance_Totale_W || 0,
        unit: 'W'
    },

    // État de charge
    soc: {
        value: msg.payload.SOC_pourcentage_P || 0,
        unit: '%'
    },

    // État de santé
    soh: {
        value: msg.payload.SOH_pourcentage_P || 0,
        unit: '%'
    },

    // Capacité
    capacite: {
        restante: msg.payload.Capacite_restante_Ah || 0,
        totale: msg.payload.Capacite_batterie_Ah || 0,
        unit: 'Ah'
    },

    // Cellules
    cellules: {
        count: cellVoltages.length,
        voltages: cellVoltages,
        minVoltage: minVoltage,
        maxVoltage: maxVoltage,
        avgVoltage: avgVoltage,
        balance: voltageBalance // Différence V entre la plus haute et plus basse
    },

    // Températures
    temperatures: {
        sensors: temperatures,
        max: maxTemp,
        min: minTemp
    },

    // États des switchs
    switches: {
        charge: msg.payload.Switch_Charge_B === 1,
        decharge: msg.payload.Switch_Decharge_B === 1,
        balance: msg.payload.Switch_Balance_B === 1,
        heating: msg.payload.Heating_B === 1
    },

    // Équilibrage
    balance: {
        courant: msg.payload.Balance_courant_A || 0,
        action: msg.payload.Balance_Action_B === 1,
        unit: 'A'
    },

    // Cycles et runtime
    maintenance: {
        nombreCycles: msg.payload.Nombre_Cycle_N || 0,
        capaciteCycles: msg.payload.Cycle_Capacite_Ah || 0,
        runtimeTotal: msg.payload.Total_runtime_S || 0,
        runtimeHours: ((msg.payload.Total_runtime_S || 0) / 3600).toFixed(2)
    }
};

// Passer les données formatées au message
msg.payload = formattedData;

return msg;

// Récupérer l'adresse du BMS
const bmsAddress = global.get('slaveAddress-Trame1') || '1';
const d = msg.payload;

// Calcul de l'uptime
const days = Math.floor(d.Uptime_S / (24 * 3600));
const hours = Math.floor((d.Uptime_S % (24 * 3600)) / 3600);

// Construire l'objet formaté complet
msg.payload = {
    bmsAddress: bmsAddress,
    timestamp: new Date().toISOString(),
    modele: d.BMS_A,
    serie: d.SerialNb_N,
    marque: d.Brand_A,
    firmware: d.FW_A,
    software: d.SW_N,
    powerCount: d.Power_count_N,
    uptime: days + "j " + hours + "h",
    dateFab: d.Manufacturing_date_N,
    buzzer: {
        trigger: d.LCD_buzzer_trigger_value_N,
        release: d.LCD_buzzer_release_value_N
    },
    params: {
        chargeV: d.Request_Charge_voltage_Time_H,
        floatV: d.Request_Float_voltage_Time_H,
        canProt: d.CAN_protocol_number_N
    }
};

return msg;

