    if (hasMaster) {
        slots.push({
            uiIndex: 1,
            entitySuffix: "master",
            heading: "Batt-Master",
            socName: "Soc batt Master"
        });

        for (let s = 2; s <= totalCount; s++) {
            slots.push({
                uiIndex: s,
                entitySuffix: String(s),
                heading: `Batt-${s}`,
                socName: `Soc batt ${s}`
            });
        }
    } else {
        for (let s = 1; s <= totalCount; s++) {
            slots.push({
                uiIndex: s,
                entitySuffix: String(s),
                heading: `Batt-${s}`,
                socName: `Soc batt ${s}`
            });
        }
    }

    return slots;
