function getPremiumDashboardMode() {
    return String(
        global.get("premium.dashboard_mode") ||
        global.get("config.premiumDashboardMode") ||
        "legacy"
    ).toLowerCase();
}
const premiumDashboardMode = getPremiumDashboardMode();
if (premiumDashboardMode === "html") {
    node.status({ fill: "blue", shape: "ring", text: "mode HTML -> dashboard Lovelace ignoré" });
    return null;
}

function isTrue(v) {
    return v === true || v === "true" || v === 1 || v === "1";
}

// Vraie config issue du noeud traitement des variables
const broadcastingEnabled =
    isTrue(global.get("bms_broadcasting")) ||
    isTrue(flow.get("bms_broadcasting")) ||
    isTrue(global.get("config.bms_broadcasting")) ||
    isTrue(global.get("config.bmsBroadcasting"));

const hasMaster = broadcastingEnabled;

// nb_jkbms = nombre TOTAL de batteries
const totalCount = Math.max(1, Number(global.get("nb_jkbms")) || 1);

// Vraie config issue du noeud traitement des variables
const customCardsInstalled =
    global.get("config.dashboardCustomCardsInstalled") === true ||
