        global.get("dashboardLanguage") ||
        "fr"
    ).toLowerCase();

// Dashboard cible
const DASHBOARD_TITLE = "Smart JK-BMS 2";
const DASHBOARD_FILE = "/config/dashboards/smart_jkbms_2.json";
