const DASHBOARD_URL_PATH = "smart-jkbms-2";
const BASE_DASHBOARD_PATH = "/smart-jkbms-2";

function circledNumber(n) {
    const map = {
        1: "❶", 2: "❷", 3: "❸", 4: "❹", 5: "❺",
        6: "❻", 7: "❼", 8: "❽", 9: "❾", 10: "❿"
    };
    return map[n] || String(n);
}

function buildBmsSlots() {
    const slots = [];

    if (hasMaster) {
        slots.push({ uiIndex: 1, entitySuffix: "master" });

        for (let s = 2; s <= totalCount; s++) {
            slots.push({ uiIndex: s, entitySuffix: String(s) });
        }
    } else {
        for (let s = 1; s <= totalCount; s++) {
            slots.push({ uiIndex: s, entitySuffix: String(s) });
        }
    }

    return slots;
}

const bmsSlots = buildBmsSlots();

function entityBase(slot) {
    return `bms_${slot.entitySuffix}`;
}

function titleIndex(slot) {
    return slot.uiIndex;
}

function titleText(slot) {
    return slot.entitySuffix === "master" ? "Master" : `JK-BMS ${slot.uiIndex}`;
}

function titleEntityText(slot) {
    return slot.entitySuffix === "master" ? "BMS_master" : `BMS_${slot.uiIndex}`;
}

function btnBadge(name, navPath, bg, color = "white") {
    return {
        type: "custom:button-card",
        name,
        tap_action: {
            action: "navigate",
            navigation_path: navPath
        },
        styles: {
            card: [
                { color },
                { "background-color": bg },
                { "border-radius": "10px" },
                { padding: "10px" },
                { margin: "10px" }
            ]
        },
        layout_options: {
            grid_columns: 1,
            grid_rows: 1
        }
    };
}

function entityCard(entity, name, extra = {}) {
    return Object.assign({
        type: "custom:mushroom-entity-card",
        entity,
        name,
        fill_container: true
    }, extra);
}

function gaugeCard(entity, name, min, max, green, yellow, red, unit) {
    return {
        type: "gauge",
        entity,
        needle: true,
        severity: { green, yellow, red },
        name,
        unit,
        theme: "ios-dark-mode-blue-red-alternative",
        grid_options: {
            columns: 4,
            rows: "auto"
        },
        max,
        min
    };
}

function binarySwitchTemplate(entity, primary) {
    return {
        type: "custom:mushroom-template-card",
        entity,
        primary,
        secondary: "{{ 'On' if is_state(entity, 'on') else 'Off' if is_state(entity, 'off') else 'Unknown' }}",
        icon: "{{ 'mdi:toggle-switch' if is_state(entity, 'on') else 'mdi:toggle-switch-off' if is_state(entity, 'off') else 'mdi:help-circle' }}",
        icon_color: "{{ 'green' if is_state(entity, 'on') else 'red' if is_state(entity, 'off') else 'grey' }}",
        grid_options: {
            columns: 4,
            rows: 1
        },
        tap_action: {
            action: "more-info"
        }
    };
}

