                    background: #021017;
                    border: black solid 1px !important;
                }
                .card-content {
                    padding: 8px;
                }
            `
        },
        cards: [
            {
                type: "markdown",
                content
            }
        ],
        grid_options: {
            columns: 12,
            rows: "auto"
