    if (!fsCtx || typeof fsCtx.readFileSync !== "function") return {};

    const paths = [
        "/data/options.json",
        "/addon/options.json",
        "/config/options.json"
    ];

    for (const p of paths) {
        try {
            if (fsCtx.existsSync && !fsCtx.existsSync(p)) continue;
            const raw = fsCtx.readFileSync(p, "utf8");
            const obj = JSON.parse(raw);
            if (obj && typeof obj === "object") return obj;
