  nombre_cycle:['cycles','cycle_count','nombre_cycle'],
  soh_pourcentage:['soh_pourcentage','soh','state_of_health'],
  mos_temp:['mos_temperature','mos_temp','mosfet_temperature']
};
function bmsSlugList(slug){const list=BMS_ENTITY_ALIASES[slug]||[slug];return [...new Set([slug,...list])]}
function bmsSortKey(v){
  const s=String(v ?? '').trim().toLowerCase();
  if(s==='master') return 1;
  const n=Number(s);
  return Number.isFinite(n)?n:999;
}

function bmsEntityCandidates(i,slug,type='sensor'){
  const prefix=type==='binary'?'binary_sensor':type;
  const ids=[];
  bmsSlugList(slug).forEach(s=>{
    // Ancien dashboard premium JK : sensor.bms_1_bms_soc_pourcentage, sensor.bms_1_bms_tension_totale_volt, etc.
    ids.push(`${prefix}.bms_${i}_bms_${s}`);
    ids.push(`${prefix}.bms_${i}_${s}`);
    ids.push(`${prefix}.bms_${i}_bms_${i}_${s}`);
    if(String(i)==='master'){
      ids.push(`${prefix}.bms_1_bms_${s}`);
      ids.push(`${prefix}.bms_1_${s}`);
      ids.push(`${prefix}.bms_1_bms_1_${s}`);
    }
  });
  return [...new Set(ids)];
}
function bmsEntity(i,slug){return bmsEntityCandidates(i,slug,'sensor').find(id=>STATES[id]) || `sensor.bms_${i}_bms_${slug}`}
function bmsState(i,slug,def='--'){return state(bmsEntityCandidates(i,slug,'sensor'),def)}
function bmsNum(i,slug){return n(bmsState(i,slug,0))}
function fmt(v,d=2){return Number.isFinite(v)?v.toFixed(d):'--'}
function pctSafe(v,total){return total>0?(v/total*100):0}
function entityAttr(id,attr,def=null){return STATES[id]?.attributes?.[attr] ?? def}

function moreInfo(entityId){
  showMiniHistory(entityId);
}
function closeMiniHistory(){
  const m=$('history_modal'); if(m)m.classList.remove('open');
}
function entityName(entityId){
  const st=STATES[entityId];
  return st?.attributes?.friendly_name || entityId;
}
function historyNumber(v){
  const m=String(v ?? '').replace(',','.').match(/-?\d+(?:\.\d+)?/);
  return m?parseFloat(m[0]):NaN;
}
function historyTime(row){
  let raw;
  if(Array.isArray(row)) raw=row[0];
  else raw=row?.last_changed ?? row?.last_updated ?? row?.lu ?? row?.lc ?? row?.t ?? row?.time;
  if(typeof raw==='number'){
    const ms=raw<20000000000?raw*1000:raw;
    return Number.isFinite(ms)?ms:NaN;
  }
  const ms=new Date(raw).getTime();
  return Number.isFinite(ms)?ms:NaN;
}
function historyState(row){
  return Array.isArray(row)?row[1]:(row?.state ?? row?.s ?? row?.value ?? row?.v);
}
function parseHistoryRows(json){
  const rows=(Array.isArray(json)&&Array.isArray(json[0]))?json[0]:(Array.isArray(json)?json:[]);
  return rows.map(r=>[historyTime(r), historyNumber(historyState(r))]).filter(p=>Number.isFinite(p[0])&&Number.isFinite(p[1]));
}
function getParentHassObject(){
  const tries=[];
  try{tries.push(window.hass)}catch(e){}
  try{if(window.parent&&window.parent!==window) tries.push(window.parent.hass)}catch(e){}
  try{if(window.top&&window.top!==window) tries.push(window.top.hass)}catch(e){}
  try{tries.push(window.parent?.document?.querySelector('home-assistant')?.hass)}catch(e){}
  try{tries.push(window.top?.document?.querySelector('home-assistant')?.hass)}catch(e){}
  return tries.find(h=>h&&typeof h==='object') || null;
}
async function historyFetchPoints(entityId,start,end){
  const path=`history/period/${encodeURIComponent(start.toISOString())}?filter_entity_id=${encodeURIComponent(entityId)}&end_time=${encodeURIComponent(end.toISOString())}&minimal_response`;
  /* V31 anti-log HA renforcé : aucun fetch direct vers /api/history.
     On utilise seulement le pont Home Assistant parent (hass.callApi) quand le
     dashboard est affiché dans Home Assistant. Cela évite les notifications
     "Login attempt failed" provoquées par des requêtes avec cookie/token invalide. */
  const hassObj=getParentHassObject();
  if(hassObj && typeof hassObj.callApi==='function'){
    try{
      const json=await hassObj.callApi('GET', path);
      const pts=parseHistoryRows(json);
      if(pts.length) return pts;
    }catch(e){ console.warn('Historique HA parent indisponible', e); }
  }
  return [];
}

function historyBmsIds(){
  const broadcasting=refreshBroadcastingMode();
  const keys=new Set();
  const all=Object.keys(STATES||{});
  if(broadcasting) keys.add('master');
  all.forEach(id=>{
    const m=id.match(/^(?:sensor|binary_sensor|number|switch)\.bms_(\d+)_/i);
    if(m){const n=Number(m[1]); if(!(broadcasting && n===1)) keys.add(n)}
  });
  if(!keys.size){
    if(broadcasting){keys.add('master');for(let i=2;i<=4;i++)keys.add(i)}
    else{for(let i=1;i<=4;i++)keys.add(i)}
  }
  return [...keys].sort((a,b)=>bmsSortKey(a)-bmsSortKey(b));
}
function historyBmsEntity(i, slug){
  try{ if(typeof bmsHistEntity === 'function') return bmsHistEntity(i, slug); }catch(e){}
  const candidates=[
    `sensor.bms_${i}_bms_${slug}`,
    `sensor.bms_${i}_${slug}`,
    `sensor.bms_${i}_bms_${i}_${slug}`
  ];
  return candidates.find(e=>STATES&&STATES[e]) || candidates[0];
}
async function historyBmsAggregate(slug,start,end,mode='avg'){
  const series=[];
  for(const i of historyBmsIds()){
    try{
      const ent=historyBmsEntity(i,slug);
      const pts=await historyFetchPoints(ent,start,end);
      pts.forEach(p=>series.push([p[0],p[1],i]));
    }catch(e){}
  }
  const buckets=new Map();
  series.forEach(([t,v])=>{
    const k=Math.round(t/300000)*300000;
    const b=buckets.get(k)||[];
    b.push(v);
    buckets.set(k,b);
  });
  return [...buckets.entries()].map(([t,vals])=>{
    let v=0;
    if(mode==='sum') v=vals.reduce((a,b)=>a+b,0);
    else if(mode==='max') v=Math.max(...vals);
    else v=vals.reduce((a,b)=>a+b,0)/Math.max(1,vals.length);
    return [Number(t),v];
  }).sort((a,b)=>a[0]-b[0]);
}
async function historyBmsAggregateAligned(slug,start,end,mode='sum'){
  const ids=historyBmsIds();
  const maxAbsBySlug={puissance_totale:10000,courant_total:220,soc_pourcentage:100,tension_totale_volt:80,cell_voltage_delta:2};
  const maxAbs=maxAbsBySlug[slug]||Number.POSITIVE_INFINITY;
  const series=[];
  for(const i of ids){
    try{
      const ent=historyBmsEntity(i,slug);
      const pts=(await historyFetchPoints(ent,start,end)).filter(p=>Number.isFinite(p[0])&&Number.isFinite(p[1])&&Math.abs(p[1])<=maxAbs).sort((a,b)=>a[0]-b[0]);
      if(pts.length) series.push({id:i,pts});
    }catch(e){}
  }
  if(!series.length) return [];
  const isMob=!!((window.matchMedia&&window.matchMedia('(max-width: 760px)').matches)||(window.matchMedia&&window.matchMedia('(pointer: coarse)').matches));
  const bucketMs=isMob?180000:300000, maxAgeMs=900000;
  const startMs=Math.ceil(start.getTime()/bucketMs)*bucketMs, endMs=end.getTime();
  const idxs=series.map(()=>0), out=[];
  for(let t=startMs;t<=endMs;t+=bucketMs){
    const vals=[];
    for(let s=0;s<series.length;s++){
      const pts=series[s].pts;
      while(idxs[s]+1<pts.length && pts[idxs[s]+1][0]<=t) idxs[s]++;
      const p=pts[idxs[s]];
      if(p && p[0]<=t && (t-p[0])<=maxAgeMs) vals.push(p[1]);
    }
    if(vals.length){
      let v=0;
      if(mode==='avg') v=vals.reduce((a,b)=>a+b,0)/vals.length;
      else if(mode==='max') v=Math.max(...vals);
      else v=vals.reduce((a,b)=>a+b,0);
      out.push([t,v]);
    }
  }
  const liveVals=ids.map(i=>bmsNum(i,slug)).filter(v=>Number.isFinite(v)&&Math.abs(v)<=maxAbs);
  if(liveVals.length){
    let live=0;
    if(mode==='avg') live=liveVals.reduce((a,b)=>a+b,0)/liveVals.length;
    else if(mode==='max') live=Math.max(...liveVals);
    else live=liveVals.reduce((a,b)=>a+b,0);
    out.push([endMs,live]);
  }
  return out.sort((a,b)=>a[0]-b[0]);
}
async function historyBmsAverage(slug,start,end){
  return historyBmsAggregate(slug,start,end,'avg');
}
async function showMiniHistory(entityId){
  if(!entityId) return;
  const modal=$('history_modal'), title=$('history_title'), sub=$('history_sub'), body=$('history_body');
  if(!modal||!body) return;
  modal.classList.add('open');
  if(title) title.textContent=entityName(entityId);
  const isMobileHist = !!((window.matchMedia&&window.matchMedia('(max-width: 760px)').matches) || (window.matchMedia&&window.matchMedia('(pointer: coarse)').matches));
  const histHours = isMobileHist ? 12 : 24;
  const end=new Date();
  const start=new Date(end.getTime()-histHours*3600*1000);
  if(sub) sub.textContent=entityId+' · dernières '+histHours+'h';
  body.innerHTML='<div class="history-empty">Chargement de l historique...</div>';
  try{
    window.__svHistoryCache=window.__svHistoryCache||{};
    const cached=window.__svHistoryCache[entityId];
    if(cached&&Date.now()-cached.time<(isMobileHist?120000:60000)){renderMiniHistory(entityId,cached.pts);return}

    // Smartphone : affichage instantané avec la valeur actuelle, puis remplacement par l'historique réel dès qu'il arrive.
    if(isMobileHist){
      let instant=historyNumber(STATES[entityId]?.state);
      if(!Number.isFinite(instant) && /^sensor\.bms_globales_puissance_totale$/i.test(entityId)) instant=historyBmsIds().reduce((a,i)=>a+bmsNum(i,'puissance_totale'),0);
      if(!Number.isFinite(instant) && /^sensor\.bms_globales_courant_total$/i.test(entityId)) instant=historyBmsIds().reduce((a,i)=>a+bmsNum(i,'courant_total'),0);
      if(!Number.isFinite(instant) && /^sensor\.bms_globales_soc_pourcentage$/i.test(entityId)){
        const vals=historyBmsIds().map(i=>bmsNum(i,'soc_pourcentage')).filter(Number.isFinite);
        if(vals.length) instant=vals.reduce((a,b)=>a+b,0)/vals.length;
      }
      if(!Number.isFinite(instant) && /^sensor\.bms_globales_tension_moyenne$/i.test(entityId)){
        const vals=historyBmsIds().map(i=>bmsNum(i,'tension_totale_volt')).filter(Number.isFinite);
        if(vals.length) instant=vals.reduce((a,b)=>a+b,0)/vals.length;
      }
      if(!Number.isFinite(instant) && /^sensor\.bms_globales_delta_max$/i.test(entityId)){
        const vals=historyBmsIds().map(i=>bmsNum(i,'cell_voltage_delta')).filter(Number.isFinite);
        if(vals.length) instant=Math.max(...vals);
      }
      if(Number.isFinite(instant)){
        const quickPts=[[start.getTime(),instant],[end.getTime(),instant]];
        window.__svHistoryRange=window.__svHistoryRange||{};
        window.__svHistoryRange[entityId]=[start.getTime(),end.getTime()];
        renderMiniHistory(entityId,quickPts);
        await new Promise(r=>setTimeout(r,0));
      }
    }

    let pts=[];
    const isGlobalPower=/^sensor\.bms_globales_puissance_totale$/i.test(entityId);
    const isGlobalCurrent=/^sensor\.bms_globales_courant_total$/i.test(entityId);
    if(isGlobalPower){
      // Power global = somme réelle des capteurs power de chaque BMS, pas l'ancien capteur global.
      pts=await historyBmsAggregateAligned('puissance_totale',start,end,'sum');
      if(!pts.length) pts=await historyFetchPoints(entityId,start,end);
    }else if(isGlobalCurrent){
      // Courant global = somme réelle des capteurs courant de chaque BMS.
      pts=await historyBmsAggregateAligned('courant_total',start,end,'sum');
      if(!pts.length) pts=await historyFetchPoints(entityId,start,end);
    }else{
