}
function archiveValue(item,kind){
  const total=itemNumber(item,['savings_vs_no_solar','total_savings','savings','home_supply_savings','value','total']);
  const battery=itemNumber(item,['battery_discharge_value','battery_savings','battery_value','battery']);
  const solarFromSavings=itemNumber(item,['solar_savings_part']);
  const solar=Math.max(0, solarFromSavings || (total - battery));
