function bmsBar(value,min,max){
  const v=Number(value);
  const lo=Number(min), hi=Number(max);
  if(!Number.isFinite(v)||!Number.isFinite(lo)||!Number.isFinite(hi)||hi<=lo) return '';
  const clamp=(x,a,b)=>Math.max(a,Math.min(b,x));
  const pct=x=>clamp((x-lo)/(hi-lo)*100,0,100);
  if(lo<0 && hi>0){
    const z=pct(0), p=pct(v);
    const left=Math.min(z,p), width=Math.abs(p-z);
    return `<div class="sv-scale-bar"><span class="sv-scale-zero" style="left:${z.toFixed(2)}%"></span><span class="sv-scale-fill" style="left:${left.toFixed(2)}%;width:${width.toFixed(2)}%"></span></div>`;
  }
  return `<div class="sv-scale-bar"><span class="sv-scale-fill" style="left:0;width:${pct(v).toFixed(2)}%"></span></div>`;
}
