function detectBroadcastingMode(){
  if(BMS_BROADCASTING_FROM_CONFIG===true || BMS_BROADCASTING===true)return true;
  const all=Object.keys(STATES||{});
  if(all.some(id=>/^(?:sensor|binary_sensor|number|switch)\.bms_master_/i.test(id)))return true;
  function directCandidates(key, slug){
    const ids=[];
    bmsSlugList(slug).forEach(s=>{
      ids.push('sensor.bms_'+key+'_bms_'+s);
      ids.push('sensor.bms_'+key+'_'+s);
      ids.push('sensor.bms_'+key+'_bms_'+key+'_'+s);
    });
    return ids;
  }
  function directNum(key, slug){const v=n(state(directCandidates(key,slug),0));return Number.isFinite(v)?v:0;}
  function directHasData(key){
    return directNum(key,'soc_pourcentage')>0.5 || directNum(key,'tension_totale_volt')>10 || Math.abs(directNum(key,'puissance_totale'))>1 || Math.abs(directNum(key,'courant_total'))>0.1 || directNum(key,'cell_voltage_average')>2 || Math.abs(directNum(key,'cell_voltage_delta'))>0.0001 || directNum(key,'soh_pourcentage')>0.5 || directNum(key,'mos_temp')>1;
