function findAccessToken(obj, depth=0){
  if(!obj || depth>8) return null;
  if(typeof obj === 'string'){
    const t=obj.trim();
    if(t.length>40 && (t.split('.').length>=2 || t.startsWith('eyJ'))) return t;
    return null;
  }
  if(typeof obj !== 'object') return null;
  for(const k of ['access_token','accessToken','token','llat']){
    if(typeof obj[k] === 'string' && obj[k].length>30) return obj[k];
  }
  for(const v of Object.values(obj)){
    const found=findAccessToken(v, depth+1);
    if(found) return found;
  }
  return null;
}
