let HA_AUTH_BLOCKED=false;
async function getTokenFromHassConnection(){
  /* V31 anti-log HA : désactivé.
     Récupérer automatiquement un token depuis les objets internes HA peut tomber
     sur un vieux jeton et générer des notifications "Login attempt failed".
     Le dashboard fonctionne d'abord via le pont HA parent. En accès direct, seul
     un token manuel explicitement enregistré avec sv_manual_token_enabled est utilisé. */
