function tokenFromUrl(){
  try{
    const u=new URL(location.href);
    const q=u.searchParams.get('token') || u.searchParams.get('ha_token');
    if(q && q.length>30) return q.trim();
    const m=String(location.hash||'').match(/(?:token|ha_token)=([^&]+)/i);
    if(m) return decodeURIComponent(m[1]).trim();
  }catch(e){}
  return null;
}
async function getToken(){
  /* V31 anti-log HA : pas d'auto-récupération de token.
     On ignore volontairement les anciens tokens stockés afin de ne plus créer de
     tentatives d'authentification invalides dans Home Assistant. */
  try{
    if(localStorage.getItem('sv_manual_token_enabled')==='1'){
      const t=getTokenFromStorageArea(window.localStorage) || getTokenFromStorageArea(window.sessionStorage);
      if(t) return t;
    }else{
      clearManualHaToken();
    }
  }catch(e){}
  return null;
}

