  const roots=[];
  function push(x){
    try{ if(x && !seen.has(x)){seen.add(x); roots.push(x);} }catch(e){}
  }
  try{push(window.hass)}catch(e){}
  try{if(window.parent && window.parent!==window) push(window.parent.hass)}catch(e){}
  try{if(window.top && window.top!==window) push(window.top.hass)}catch(e){}
  function inspectNode(node, depth){
    if(!node || depth>6) return null;
    try{
      const h=node.hass || node._hass || node.__hass;
      if(h && h.states && typeof h.states==='object') return h;
    }catch(e){}
    try{
      if(node.shadowRoot){
        const r=inspectNode(node.shadowRoot, depth+1); if(r) return r;
      }
    }catch(e){}
    try{
      const children=node.children || node.childNodes || [];
      const max=Math.min(children.length||0, 160);
      for(let i=0;i<max;i++){
        const r=inspectNode(children[i], depth+1); if(r) return r;
      }
    }catch(e){}
    return null;
  }
  const docs=[];
  try{docs.push(document)}catch(e){}
  try{if(window.parent && window.parent!==window && window.parent.document) docs.push(window.parent.document)}catch(e){}
  try{if(window.top && window.top!==window && window.top.document) docs.push(window.top.document)}catch(e){}
  for(const d of docs){
    try{push(d.querySelector('home-assistant')?.hass)}catch(e){}
    try{const h=inspectNode(d,0); if(h) return h;}catch(e){}
  }
  for(const h of roots){
    try{ if(h && h.states && typeof h.states==='object') return h; }catch(e){}
  }
  return null;
}

let PARENT_HASS_TIMER=null;
let PARENT_HASS_PROBE=null;
function startParentHassBridge(){
  const h=getParentHassObject();
  if(!h || !h.states) return false;
  removeHaTokenNotice();
  HA_TOKEN=null;
  try{ if(WS) WS.close(); }catch(e){}
  STATES=h.states;
  try{update()}catch(e){console.error(e)}
  if(PARENT_HASS_TIMER) clearInterval(PARENT_HASS_TIMER);
  PARENT_HASS_TIMER=setInterval(()=>{
    const hh=getParentHassObject();
    if(hh && hh.states){
      STATES=hh.states;
      scheduleUpdate();
    }
  }, window.__SV_DESKTOP_LITE ? 1500 : 1000);
  return true;
}
function startParentProbe(){
  if(PARENT_HASS_PROBE) return;
  let tries=0;
  PARENT_HASS_PROBE=setInterval(()=>{
    tries++;
    if(startParentHassBridge() || tries>40){
      clearInterval(PARENT_HASS_PROBE);
      PARENT_HASS_PROBE=null;
    }
  },500);
}
let STARTING=false;
let CLOCK_TIMER=null;
async function start(){
  if(STARTING) return;
  STARTING=true;
  try{
    if(!CLOCK_TIMER) CLOCK_TIMER=setInterval(()=>set('clock',new Date().toLocaleTimeString()),1000);
    try{renderInverters()}catch(e){console.error(e)}
    try{updateEcoCharts()}catch(e){console.error(e)}
    if(startParentHassBridge()){
      console.info('Home Assistant states récupérés automatiquement depuis le parent HA');
      return;
    }
    /* V31 : aucune connexion automatique à /api/websocket.
       On évite ainsi les logs HA aléatoires quand le dashboard est intégré dans HA.
       Si le pont parent n'est pas prêt, on le recherche quelques secondes sans auth. */
    startParentProbe();
    const token=await getToken();
    HA_TOKEN=token;
    if(token){
      connectWebsocket(token);
    }else{
      try{update()}catch(e){console.error(e)}
      // Pas de panneau intrusif tant qu'on est affiché dans Home Assistant : le pont parent peut arriver juste après.
      setTimeout(()=>{ if(!getParentHassObject() && !WS) showHaTokenNotice(); },7000);
    }
  } finally {
    setTimeout(()=>{STARTING=false},500);
  }
}


