function v28Words(slug){return String(slug||'').toLowerCase().split('_').filter(w=>w && !['param','diag','pct'].includes(w));}
function v28FindEntity(type,i,slug,extra=[]){
  const base=`${type}.voltronic_inv${i}`;
  const exact=[`${base}_param_${slug}`,`${base}_${slug}`,`${type}.voltronic_inverter_${i}_param_${slug}`,`${type}.voltronic_inverter_${i}_${slug}`,...extra];
  for(const id of exact){ if(STATES[id]) return id; }
  const words=v28Words(slug);
  const all=Object.keys(STATES||{});
  const hit=all.find(id=>id.startsWith(type+'.') && id.toLowerCase().includes(`voltronic_inv${i}`) && words.every(w=>id.toLowerCase().includes(w)));
  return hit || exact[0];
}
paramEntity=function(i,type,slug){return v28FindEntity(type,i,slug);};
diagEntity=function(i,type,slug){
  if(type==='switch') return v28FindEntity('switch',i,slug,[`switch.voltronic_inv${i}_${slug}`]);
  if(type==='text') return v28FindEntity('text',i,slug,[`text.voltronic_inv${i}_${slug}`]);
  return v28FindEntity('sensor',i,slug,[sensor(i,slug)]);
};
function v28ExistsEntity(ent,type){return !!STATES[ent] || type==='text';}
invParamsV24=function(i){
  return `<div class="param-pack"><div class="param-title">🔧 Commandes onduleur ${i}</div>${PARAM_DEFS.map(([type,slug,name])=>{const ent=paramEntity(i,type,slug); const exists=!!STATES[ent]; return `<div class="param-row ${exists?'':'param-missing'}"><div><div class="param-name">${name}</div><div class="param-entity">${ent}${exists?'':' · non trouvé'}</div></div><div class="param-control">${exists?paramControl(ent,type):'<span class="small">Entité absente</span>'}</div></div>`}).join('')}</div>`;
};
invDiagV24=function(i){
  return `<div class="diag-pack"><div class="diag-title"><span>🩺 Diagnostic onduleur ${i}</span><span class="diag-status-pill">Live</span></div><div class="diag-grid">${DIAG_DEFS.map(([type,slug,name])=>{const ent=diagEntity(i,type,slug); const exists=v28ExistsEntity(ent,type); const val=diagValue(ent); const big=['diag_raw_command','diag_raw_response','diag_fault_details','diag_warn_details','battery_health_reason'].includes(slug); return `<div class="diag-card ${big?'big':''} ${diagCardClass(slug,val)} ${exists?'':'param-missing'}"><div class="label">${name}</div><div class="value">${exists?escAttr(val):'--'}</div><div class="small">${ent}${exists?'':' · non trouvé'}</div>${exists?diagControl(ent,type,val):''}</div>`}).join('')}</div></div>`;
};
v27TempInvWide=function(i){
  const slugs=['inverter_heat_sink_temp','max_internal_temperature','q1_internal_temperature','q1_inverter_temperature','q1_boost_temperature','inverter_temperature','internal_temperature','diag_temperature','temperature','heat_sink_temperature','radiator_temperature'];
  for(const slug of slugs){const v=invNum(i,slug); if(Number.isFinite(v)&&v!==0) return v;}
  const prefix=`sensor.voltronic_inv${i}`;
  for(const [id,st] of Object.entries(STATES||{})){
    const low=id.toLowerCase();
    if(id.startsWith(prefix) && (low.includes('temp')||low.includes('temperature')||low.includes('heat'))){
      const v=parseFloat(st?.state); if(Number.isFinite(v)&&v!==0) return v;
    }
  }
  return 0;
};
function v28RenderCoreTemp(){
  const extra=document.querySelector('.inverter-core .core-extra');
  if(extra && !$('core_temp_chip')) extra.insertAdjacentHTML('beforeend','<span id="core_temp_chip">🌡️ <b id="core_temp">--</b>°C</span>');
  const meta=document.querySelector('.inverter-core .meta');
  if(meta && !$('core_temp_line')) meta.insertAdjacentHTML('afterend','<div id="core_temp_line" class="core-temp-line">🌡️ Temp. onduleurs moyenne : <b id="core_temp_line_val">--</b> °C</div>');
  const t=v27TempInvAvg();
  if($('core_temp')) set('core_temp',t?t.toFixed(1):'--');
  if($('core_temp_line_val')) set('core_temp_line_val',t?t.toFixed(1):'--');
}
const __v28OldExtras=v24UpdateGlobalExtras;
v24UpdateGlobalExtras=function(){try{__v28OldExtras()}catch(e){console.error('V28 old extras error',e)}; try{v28RenderCoreTemp()}catch(e){console.error('V28 temp error',e)}};
showInvView=function(id,btn){
  window.__activeInvView=id;
  document.querySelectorAll('#inverters .inv-view').forEach(v=>v.classList.remove('active'));
  const e=$(id); if(e)e.classList.add('active');
  document.querySelectorAll('#inverters .inv-subnav .subtab').forEach(b=>b.classList.remove('active'));
  if(btn)btn.classList.add('active');
  try{renderInverters(true);v27UpdateInverterValues();}catch(err){console.error('showInvView rebuild',err)}
};
showInvInner=function(i,which,btn){
  window.__activeInvInner=window.__activeInvInner||{};window.__activeInvInner[i]=which;
  try{renderInverters(true);v27UpdateInverterValues();}catch(err){console.error('showInvInner rebuild',err)}
};

const __v24OldUpdate=update;
update=function(){__v24OldUpdate(); try{v24UpdateGlobalExtras(); renderInverters(false);v27UpdateInverterValues();}catch(e){console.error('V27 patch error',e)}};

start();
