<script id="SV_LIGHT_BMS_HISTORY">
(function(){
  function isMobileLite(){
    try{
      return !!((window.matchMedia&&window.matchMedia('(max-width: 760px)').matches) || (window.matchMedia&&window.matchMedia('(pointer: coarse)').matches));
    }catch(e){return false}
  }
  function currentBmsId(){
    try{
      if(typeof BMS_VIEW!=='undefined' && BMS_VIEW && BMS_VIEW!=='overview') return String(BMS_VIEW);
    }catch(e){}
    const title=document.querySelector('#jkbms .bms-pack:not(.clickable) .bms-title')?.textContent||'';
    const m=title.match(/Batt-(Master|\d+)|Batterie\s+(Master|\d+)/i);
    return m?String(m[1]||m[2]).toLowerCase():'';
  }
  function bmsHistEntity(i,slug){
    if(!i||!slug) return '';
    try{
      if(typeof bmsEntity==='function'){
        const e=bmsEntity(i,slug);
        if(e) return e;
      }
    }catch(e){}
    const s=String(i).toLowerCase();
    const candidates=[
      `sensor.bms_${s}_bms_${slug}`,
      `sensor.bms_${s}_${slug}`,
      `sensor.bms_${s}_bms_${s}_${slug}`
    ];
    if(s==='master'){
      candidates.push(
        `sensor.bms_1_bms_${slug}`,
        `sensor.bms_1_${slug}`,
        `sensor.bms_1_bms_1_${slug}`
      );
    }
    try{
      const found=candidates.find(id=>STATES&&STATES[id]);
      if(found) return found;
      const words=String(slug).toLowerCase().split('_').filter(Boolean);
      const prefixes=[
        `sensor.bms_${s}_bms_`,
        `sensor.bms_${s}_`,
        `sensor.bms_${s}_bms_${s}_`
      ];
      if(s==='master') prefixes.push('sensor.bms_1_bms_','sensor.bms_1_','sensor.bms_1_bms_1_');
      const hit=Object.keys(STATES||{}).find(id=>{
        const low=id.toLowerCase();
        return prefixes.some(p=>low.startsWith(p))&&words.every(w=>low.includes(w));
      });
      if(hit) return hit;
    }catch(e){}
    return candidates[candidates.length-1]||candidates[0];
  }
  function entityFromText(el){
    const text=el?.querySelector?.('.small,.bms-param-entity,.param-entity')?.textContent||'';
    const m=String(text).match(/(?:sensor|binary_sensor|number|switch|select|text)\.[a-zA-Z0-9_]+/);
    return m?m[0]:'';
  }
  function entityForTarget(target){
    if(!target||target.closest('button,input,select,textarea,[data-no-hist="1"]')) return '';
    const i=currentBmsId();
    if(!i) return '';
    const explicit=target.closest('[data-hist],[data-default-hist]');
    if(explicit) return explicit.dataset.hist||explicit.dataset.defaultHist||'';
    const textEnt=entityFromText(target);
    if(textEnt) return textEnt;
    const pack=target.closest('#jkbms .bms-pack');
    if(!pack) return '';
    const headerCards=[...pack.querySelectorAll(':scope > .diag-wow > .diag-wow-card')];
    const headerIndex=headerCards.indexOf(target);
    if(headerIndex>=0){
      return bmsHistEntity(i,['soc_pourcentage','tension_totale_volt','puissance_totale','cell_voltage_delta'][headerIndex]);
    }
    const soc=target.closest('.soc-ring');
    if(soc&&pack.contains(soc)) return bmsHistEntity(i,'soc_pourcentage');
    const liveKpis=[...pack.querySelectorAll('.bms-main-grid .bms-kpi')];
    const kpiIndex=liveKpis.indexOf(target);
    if(kpiIndex>=0){
      return bmsHistEntity(i,['tension_totale_volt','puissance_totale','courant_total','cell_voltage_average','cell_voltage_delta','nombre_cycle'][kpiIndex]);
    }
    const liveCells=[...pack.querySelectorAll('.bms-cells .cell-card')];
    const cellIndex=liveCells.indexOf(target);
    if(cellIndex>=0){
      return bmsHistEntity(i,['cell_voltage_min_value','cell_voltage_max_value','soh_pourcentage','mos_temp'][cellIndex]);
    }
    const meter=target.closest('.cell-meter');
    if(meter&&pack.contains(meter)){
      const txt=meter.textContent||'';
      const cm=txt.match(/Cell\s+(\d+)/i);
      if(cm){
        const c=Number(cm[1]);
        const ohm=/Ω|Î©|ohm|resistance/i.test(txt);
        return bmsHistEntity(i,ohm?`cell_${c}_ohm`:`cell_${c}_volt`);
      }
    }
    return '';
  }
  function markHistoryTargets(){
    if(!currentBmsId()) return;
    document.querySelectorAll('#jkbms .diag-wow-card,#jkbms .soc-ring,#jkbms .bms-kpi,#jkbms .cell-card,#jkbms .info-tile,#jkbms .cell-meter').forEach(el=>{
      if(el.closest('[data-no-hist="1"]')) return;
      el.style.cursor='pointer';
      el.title=el.title||'Historique';
    });
  }
  document.addEventListener('click',function(ev){
    if(!currentBmsId()) return;
    const card=ev.target.closest&&ev.target.closest('#jkbms .diag-wow-card,#jkbms .soc-ring,#jkbms .bms-kpi,#jkbms .cell-card,#jkbms .info-tile,#jkbms .cell-meter');
    if(!card) return;
    const ent=entityForTarget(card);
    if(!ent||typeof moreInfo!=='function') return;
    ev.preventDefault();
    ev.stopPropagation();
    ev.stopImmediatePropagation?.();
    moreInfo(ent);
  },true);
  try{
    const baseSetBmsView=window.setBmsView||setBmsView;
    window.setBmsView=setBmsView=function(){
      const r=baseSetBmsView.apply(this,arguments);
      setTimeout(markHistoryTargets,0);
      return r;
    };
    const baseSetBmsTab=window.setBmsTab||setBmsTab;
    window.setBmsTab=setBmsTab=function(){
      const r=baseSetBmsTab.apply(this,arguments);
      setTimeout(markHistoryTargets,0);
      return r;
    };
  }catch(e){}
  document.addEventListener('DOMContentLoaded',()=>setTimeout(markHistoryTargets,300));

  if(isMobileLite()){
    try{
      let pending=false,last=0;
      const minDelay=2200;
      const baseUpdate=typeof update==='function'?update:null;
      if(typeof scheduleUpdate==='function' && baseUpdate){
        const mobileSchedule=function(){
          if(pending) return;
          const wait=Math.max(0,minDelay-(Date.now()-last));
          pending=true;
          setTimeout(()=>{
            pending=false;
            if(document.hidden) return;
            last=Date.now();
            try{baseUpdate()}catch(e){console.error('mobile update',e)}
          },wait);
        };
        scheduleUpdate=mobileSchedule;
        window.scheduleUpdate=mobileSchedule;
      }
      document.addEventListener('visibilitychange',()=>{
        if(!document.hidden && typeof scheduleUpdate==='function') scheduleUpdate();
      });
    }catch(e){}
  }
})();
</script>


