<script id="SV_DESKTOP_PERF_PATCH">
(function(){
  function isCoarseOrMobile(){
    try{
      return !!((window.matchMedia&&window.matchMedia('(max-width: 760px)').matches) || (window.matchMedia&&window.matchMedia('(pointer: coarse)').matches));
    }catch(e){return false}
  }
  function lowSpecDesktop(){
    if(isCoarseOrMobile()) return false;
    try{
      if(localStorage.getItem('sv_desktop_lite')==='1') return true;
      if(localStorage.getItem('sv_desktop_lite')==='0') return false;
    }catch(e){}
    const mem=Number(navigator.deviceMemory||0);
    const cores=Number(navigator.hardwareConcurrency||0);
    if(mem && mem<=4) return true;
    if(cores && cores<=4) return true;
    return false;
  }
  const lite=lowSpecDesktop();
  window.__SV_DESKTOP_LITE = lite;
  if(lite){
    try{document.documentElement.classList.add('sv-lite-desktop')}catch(e){}
  }

  /* Anti-surcharge PC: même sur ordinateur, on évite les rafales d'events HA.
     - PC normal: max ~1 update / 0,8 s
     - PC léger détecté: max ~1 update / 1,45 s
     Le contenu reste identique, seule la fréquence de recalcul DOM est limitée. */
  if(isCoarseOrMobile()) return;
  try{
    let pending=false;
    let last=0;
    const minDelay=lite?1450:800;
    const baseUpdate=(typeof update==='function')?update:null;
    if(typeof scheduleUpdate==='function' && baseUpdate){
      const desktopSchedule=function(){
        if(pending) return;
        const now=Date.now();
        const wait=Math.max(0,minDelay-(now-last));
        pending=true;
        setTimeout(function(){
          pending=false;
          if(document.hidden) return;
          last=Date.now();
          try{baseUpdate()}catch(e){console.error('desktop update',e)}
        },wait);
      };
      scheduleUpdate=desktopSchedule;
      window.scheduleUpdate=desktopSchedule;
    }
    document.addEventListener('visibilitychange',function(){
      if(!document.hidden && typeof scheduleUpdate==='function') scheduleUpdate();
    });
  }catch(e){}
})();
</script>


<script id="SV_PC_HISTORY_FAST_V3">
(function(){
  /* V3 : PC = comportement léger, proche smartphone.
     On évite le piège des cartes globales qui recalculaient l'historique
     en interrogeant chaque BMS séparément. Une fenêtre = une entité = une requête HA.
     Si l'historique global n'existe pas, on garde la courbe instantanée au lieu de bloquer. */
  function svIsMobileHist(){
    try{
      return !!((window.matchMedia&&window.matchMedia('(max-width: 760px)').matches) || (window.matchMedia&&window.matchMedia('(pointer: coarse)').matches));
    }catch(e){return false}
  }
  function svBmsIdsSafe(){
    try{ return (typeof historyBmsIds==='function'?historyBmsIds():[]); }catch(e){ return []; }
  }
  function svBmsNumSafe(i,slug){
    try{ return (typeof bmsNum==='function'?bmsNum(i,slug):NaN); }catch(e){ return NaN; }
  }
  function svCurrentValue(entityId){
    let instant=NaN;
    try{ instant=historyNumber(STATES?.[entityId]?.state); }catch(e){}
    const low=String(entityId||'').toLowerCase();
    const ids=svBmsIdsSafe();
    if(!Number.isFinite(instant) && /^sensor\.bms_globales_puissance_totale$/i.test(low)){
      const vals=ids.map(i=>svBmsNumSafe(i,'puissance_totale')).filter(Number.isFinite);
      if(vals.length) instant=vals.reduce((a,b)=>a+b,0);
    }
    if(!Number.isFinite(instant) && /^sensor\.bms_globales_courant_total$/i.test(low)){
      const vals=ids.map(i=>svBmsNumSafe(i,'courant_total')).filter(Number.isFinite);
      if(vals.length) instant=vals.reduce((a,b)=>a+b,0);
    }
    if(!Number.isFinite(instant) && /^sensor\.bms_globales_soc_pourcentage$/i.test(low)){
      const vals=ids.map(i=>svBmsNumSafe(i,'soc_pourcentage')).filter(Number.isFinite);
      if(vals.length) instant=vals.reduce((a,b)=>a+b,0)/vals.length;
    }
    if(!Number.isFinite(instant) && /^sensor\.bms_globales_tension_moyenne$/i.test(low)){
      const vals=ids.map(i=>svBmsNumSafe(i,'tension_totale_volt')).filter(Number.isFinite);
      if(vals.length) instant=vals.reduce((a,b)=>a+b,0)/vals.length;
    }
    if(!Number.isFinite(instant) && /^sensor\.bms_globales_delta_max$/i.test(low)){
      const vals=ids.map(i=>svBmsNumSafe(i,'cell_voltage_delta')).filter(Number.isFinite);
      if(vals.length) instant=Math.max(...vals);
    }
    return instant;
  }
  function svCleanGlobal(entityId,pts,endMs){
    const low=String(entityId||'').toLowerCase();
    pts=(pts||[]).filter(p=>Array.isArray(p)&&Number.isFinite(p[0])&&Number.isFinite(p[1]));
    if(/^sensor\.bms_globales_courant_total$/i.test(low)){
      pts=pts.filter(p=>Math.abs(p[1])<=220).map(p=>[p[0],Math.max(-200,Math.min(200,p[1]))]);
    }
    if(/^sensor\.bms_globales_puissance_totale$/i.test(low)){
      pts=pts.filter(p=>Math.abs(p[1])<=12000).map(p=>[p[0],Math.max(-10000,Math.min(10000,p[1]))]);
    }
    const cur=svCurrentValue(entityId);
    if(Number.isFinite(cur)){
      let v=cur;
      if(/^sensor\.bms_globales_courant_total$/i.test(low)) v=Math.max(-200,Math.min(200,v));
      if(/^sensor\.bms_globales_puissance_totale$/i.test(low)) v=Math.max(-10000,Math.min(10000,v));
      pts=pts.filter(p=>p[0] < endMs-30000);
      pts.push([endMs,v]);
    }
    return pts.sort((a,b)=>a[0]-b[0]);
  }
  async function svRenderSoon(entityId,pts){
    try{ renderMiniHistory(entityId,pts); }catch(e){ console.warn('render history fast',e); }
    await new Promise(r=>requestAnimationFrame(()=>setTimeout(r,0)));
  }
  showMiniHistory=async function(entityId){
    if(!entityId) return;
    const modal=document.getElementById('history_modal'), title=document.getElementById('history_title'), sub=document.getElementById('history_sub'), body=document.getElementById('history_body');
    if(!modal||!body) return;
    const isMob=svIsMobileHist();
    const histHours=12; // même logique rapide que smartphone : moins de points à demander à HA.
    const end=new Date();
    const start=new Date(end.getTime()-histHours*3600*1000);
    const startMs=start.getTime(), endMs=end.getTime();
    const token=(window.__svHistoryToken=(window.__svHistoryToken||0)+1);
    window.__svHistoryActiveEntity=entityId;
    modal.classList.add('open');
    if(title){
      try{ title.textContent=(typeof entityName==='function'?entityName(entityId):entityId); }catch(e){ title.textContent=entityId; }
    }
    if(sub) sub.textContent=entityId+' · dernières '+histHours+'h';
    window.__svHistoryCache=window.__svHistoryCache||{};
    window.__svHistoryRange=window.__svHistoryRange||{};
    window.__svHistoryRange[entityId]=[startMs,endMs];
    const cacheKey=entityId+'|fast12h';
    const cached=window.__svHistoryCache[cacheKey]||window.__svHistoryCache[entityId];
    if(cached && Date.now()-cached.time < (isMob?120000:90000)){
      if(sub) sub.textContent=entityId+' · cache récent';
      renderMiniHistory(entityId,cached.pts);
      return;
    }
    const cur=svCurrentValue(entityId);
    let quickShown=false;
    if(Number.isFinite(cur)){
      quickShown=true;
      if(sub) sub.textContent=entityId+' · ouverture instantanée, historique réel en fond...';
      await svRenderSoon(entityId,[[startMs,cur],[endMs,cur]]);
    }else{
      body.innerHTML='<div class="history-empty">Chargement de l historique...</div>';
      await new Promise(r=>requestAnimationFrame(()=>setTimeout(r,0)));
    }
    try{
      // V4 : les cartes globales JK-BMS sont des valeurs calculées.
      // On reconstruit donc leur historique réel depuis les historiques des batteries,
      // comme dans la sous-vue Batterie, puis on ne retombe sur l'entité globale qu'en secours.
      let pts=[];
      const low=String(entityId||'').toLowerCase();
      try{
        if(/^sensor\.bms_globales_puissance_totale$/i.test(low) && typeof historyBmsAggregateAligned==='function'){
          pts=await historyBmsAggregateAligned('puissance_totale',start,end,'sum');
        }else if(/^sensor\.bms_globales_courant_total$/i.test(low) && typeof historyBmsAggregateAligned==='function'){
          pts=await historyBmsAggregateAligned('courant_total',start,end,'sum');
        }else if(/^sensor\.bms_globales_soc_pourcentage$/i.test(low)){
          if(typeof historyBmsAggregateAligned==='function') pts=await historyBmsAggregateAligned('soc_pourcentage',start,end,'avg');
          if(!pts.length && typeof historyBmsAverage==='function') pts=await historyBmsAverage('soc_pourcentage',start,end);
        }else if(/^sensor\.bms_globales_tension_moyenne$/i.test(low)){
          if(typeof historyBmsAggregateAligned==='function') pts=await historyBmsAggregateAligned('tension_totale_volt',start,end,'avg');
          if(!pts.length && typeof historyBmsAverage==='function') pts=await historyBmsAverage('tension_totale_volt',start,end);
        }else if(/^sensor\.bms_globales_delta_max$/i.test(low)){
          if(typeof historyBmsAggregateAligned==='function') pts=await historyBmsAggregateAligned('cell_voltage_delta',start,end,'max');
          if(!pts.length && typeof historyBmsAggregate==='function') pts=await historyBmsAggregate('cell_voltage_delta',start,end,'max');
        }
        if(!pts.length && typeof historyFetchPoints==='function') pts=await historyFetchPoints(entityId,start,end);
      }catch(e){ pts=[]; }
      if(token!==window.__svHistoryToken || window.__svHistoryActiveEntity!==entityId) return;
      pts=svCleanGlobal(entityId,pts,endMs);
      if(!pts.length && Number.isFinite(cur)) pts=[[startMs,cur],[endMs,cur]];
