function $(id){return document.getElementById(id)}
function n(v){const x=parseFloat(v);return Number.isFinite(x)?x:0}
function bad(v){return v==null||['unknown','unavailable','none',''].includes(String(v).toLowerCase())}
function valid(id){return STATES[id]&&!bad(STATES[id].state)}
function state(ids,d='--'){for(const id of ids){if(valid(id))return STATES[id].state}return d}
function num(ids){return n(state(ids,0))}
function set(id,v){const e=$(id);if(e)e.textContent=v}
function sensor(i,s){return `sensor.voltronic_inv${i}_${s}`}
function number(i,s){return `number.voltronic_inv${i}_param_${s}`}
function select(i,s){return `select.voltronic_inv${i}_param_${s}`}
function invNum(i,s,a=[]){return num([sensor(i,s),...a.map(x=>sensor(i,x))])}
function invState(i,s,a=[]){return state([sensor(i,s),...a.map(x=>sensor(i,x))])}
const BMS_ENTITY_ALIASES={
  soc_pourcentage:['soc_pourcentage','soc','state_of_charge'],
  tension_totale_volt:['voltage','total_voltage','tension_totale_volt'],
