  return tries.find(h=>h&&typeof h==='object') || null;
}
async function historyFetchPoints(entityId,start,end){
  const path=`history/period/${encodeURIComponent(start.toISOString())}?filter_entity_id=${encodeURIComponent(entityId)}&end_time=${encodeURIComponent(end.toISOString())}&minimal_response`;
  /* V31 anti-log HA renforcé : aucun fetch direct vers /api/history.
     On utilise seulement le pont Home Assistant parent (hass.callApi) quand le
     dashboard est affiché dans Home Assistant. Cela évite les notifications
     "Login attempt failed" provoquées par des requêtes avec cookie/token invalide. */
  const hassObj=getParentHassObject();
  if(hassObj && typeof hassObj.callApi==='function'){
    try{
      const json=await hassObj.callApi('GET', path);
      const pts=parseHistoryRows(json);
      if(pts.length) return pts;
    }catch(e){ console.warn('Historique HA parent indisponible', e); }
  }
  return [];
}

function historyBmsIds(){
  const broadcasting=refreshBroadcastingMode();
  const keys=new Set();
  const all=Object.keys(STATES||{});
  if(broadcasting) keys.add('master');
  all.forEach(id=>{
    const m=id.match(/^(?:sensor|binary_sensor|number|switch)\.bms_(\d+)_/i);
    if(m){const n=Number(m[1]); if(!(broadcasting && n===1)) keys.add(n)}
  });
  if(!keys.size){
    if(broadcasting){keys.add('master');for(let i=2;i<=4;i++)keys.add(i)}
    else{for(let i=1;i<=4;i++)keys.add(i)}
  }
  return [...keys].sort((a,b)=>bmsSortKey(a)-bmsSortKey(b));
}
function historyBmsEntity(i, slug){
  try{ if(typeof bmsHistEntity === 'function') return bmsHistEntity(i, slug); }catch(e){}
  const candidates=[
    `sensor.bms_${i}_bms_${slug}`,
    `sensor.bms_${i}_${slug}`,
    `sensor.bms_${i}_bms_${i}_${slug}`
  ];
  return candidates.find(e=>STATES&&STATES[e]) || candidates[0];
}
async function historyBmsAggregate(slug,start,end,mode='avg'){
  const series=[];
  for(const i of historyBmsIds()){
    try{
      const ent=historyBmsEntity(i,slug);
      const pts=await historyFetchPoints(ent,start,end);
      pts.forEach(p=>series.push([p[0],p[1],i]));
    }catch(e){}
  }
  const buckets=new Map();
  series.forEach(([t,v])=>{
    const k=Math.round(t/300000)*300000;
    const b=buckets.get(k)||[];
    b.push(v);
    buckets.set(k,b);
  });
  return [...buckets.entries()].map(([t,vals])=>{
    let v=0;
    if(mode==='sum') v=vals.reduce((a,b)=>a+b,0);
    else if(mode==='max') v=Math.max(...vals);
    else v=vals.reduce((a,b)=>a+b,0)/Math.max(1,vals.length);
    return [Number(t),v];
  }).sort((a,b)=>a[0]-b[0]);
}
async function historyBmsAggregateAligned(slug,start,end,mode='sum'){
  const ids=historyBmsIds();
  const maxAbsBySlug={puissance_totale:10000,courant_total:220,soc_pourcentage:100,tension_totale_volt:80,cell_voltage_delta:2};
  const maxAbs=maxAbsBySlug[slug]||Number.POSITIVE_INFINITY;
  const series=[];
  for(const i of ids){
    try{
      const ent=historyBmsEntity(i,slug);
      const pts=(await historyFetchPoints(ent,start,end)).filter(p=>Number.isFinite(p[0])&&Number.isFinite(p[1])&&Math.abs(p[1])<=maxAbs).sort((a,b)=>a[0]-b[0]);
      if(pts.length) series.push({id:i,pts});
    }catch(e){}
  }
  if(!series.length) return [];
  const isMob=!!((window.matchMedia&&window.matchMedia('(max-width: 760px)').matches)||(window.matchMedia&&window.matchMedia('(pointer: coarse)').matches));
  const bucketMs=isMob?180000:300000, maxAgeMs=900000;
  const startMs=Math.ceil(start.getTime()/bucketMs)*bucketMs, endMs=end.getTime();
  const idxs=series.map(()=>0), out=[];
  for(let t=startMs;t<=endMs;t+=bucketMs){
    const vals=[];
    for(let s=0;s<series.length;s++){
      const pts=series[s].pts;
      while(idxs[s]+1<pts.length && pts[idxs[s]+1][0]<=t) idxs[s]++;
      const p=pts[idxs[s]];
      if(p && p[0]<=t && (t-p[0])<=maxAgeMs) vals.push(p[1]);
    }
    if(vals.length){
      let v=0;
      if(mode==='avg') v=vals.reduce((a,b)=>a+b,0)/vals.length;
      else if(mode==='max') v=Math.max(...vals);
      else v=vals.reduce((a,b)=>a+b,0);
      out.push([t,v]);
    }
  }
  const liveVals=ids.map(i=>bmsNum(i,slug)).filter(v=>Number.isFinite(v)&&Math.abs(v)<=maxAbs);
  if(liveVals.length){
    let live=0;
    if(mode==='avg') live=liveVals.reduce((a,b)=>a+b,0)/liveVals.length;
    else if(mode==='max') live=Math.max(...liveVals);
    else live=liveVals.reduce((a,b)=>a+b,0);
    out.push([endMs,live]);
  }
  return out.sort((a,b)=>a[0]-b[0]);
}
async function historyBmsAverage(slug,start,end){
  return historyBmsAggregate(slug,start,end,'avg');
}
