        if(vals.length) instant=vals.reduce((a,b)=>a+b,0)/vals.length;
      }
      if(!Number.isFinite(instant) && /^sensor\.bms_globales_delta_max$/i.test(entityId)){
        const vals=historyBmsIds().map(i=>bmsNum(i,'cell_voltage_delta')).filter(Number.isFinite);
