        const vals=historyBmsIds().map(i=>historyNumber(STATES[`sensor.bms_${i}_soc_pourcentage`]?.state)).filter(Number.isFinite);
        if(vals.length){
          const avg=vals.reduce((a,b)=>a+b,0)/vals.length;
