  const n=Number(value);
  const shown=Number.isFinite(n)?n.toFixed(Math.abs(n)<10?3:2):String(value??'--');
  tip.innerHTML=`<div>${label}</div><div style="font-size:20px;color:#2ec7ff">${shown} ${unit||''}</div><div class="muted">mini historique</div>`;
  tip.style.left=Math.min(evt.clientX+14, window.innerWidth-220)+'px';
  tip.style.top=Math.min(evt.clientY+14, window.innerHeight-120)+'px';
  tip.style.display='block';
}
function hideHistoryTooltip(){
  const tip=$('history_tooltip');
  if(tip)tip.style.display='none';
  const marker=$('history_marker');
  const vline=$('history_vline');
  if(marker)marker.style.display='none';
  if(vline)vline.style.display='none';
}
function historyHover(evt, entityId){
  const cache=window.__svHistoryRenderCache||{};
  const entry=cache[entityId]||null;
  const pts=Array.isArray(entry)?entry:(entry?.pts||[]);
  if(!pts.length){return hideHistoryTooltip()}
  const rect=evt.currentTarget.getBoundingClientRect();
  const touch=evt.touches&&evt.touches.length?evt.touches[0]:(evt.changedTouches&&evt.changedTouches.length?evt.changedTouches[0]:null);
  const clientX=touch?touch.clientX:evt.clientX;
  const ratio=Math.max(0,Math.min(1,(clientX-rect.left)/Math.max(1,rect.width)));
  const minT=Number.isFinite(entry?.minT)?entry.minT:pts[0][0];
  const maxT=Number.isFinite(entry?.maxT)?entry.maxT:pts[pts.length-1][0];
  const target=minT+(maxT-minT)*ratio;
  let best=pts[0], bestDist=Math.abs(pts[0][0]-target);
  for(let i=1;i<pts.length;i++){
    const d=Math.abs(pts[i][0]-target);
    if(d<bestDist){best=pts[i];bestDist=d}
  }
  const label=new Date(best[0]).toLocaleString([], {day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit',second:'2-digit'});
  const unit=STATES[entityId]?.attributes?.unit_of_measurement || '';
  const marker=$('history_marker');
  const vline=$('history_vline');
  if(marker&&vline&&entry&&Number.isFinite(entry.minV)&&Number.isFinite(entry.maxV)){
    const x=entry.padL+(best[0]-entry.minT)/(entry.maxT-entry.minT||1)*entry.plotW;
    const y=entry.padT+entry.plotH-(best[1]-entry.minV)/(entry.maxV-entry.minV||1)*entry.plotH;
    marker.setAttribute('cx',x.toFixed(1));
    marker.setAttribute('cy',y.toFixed(1));
    marker.style.display='block';
    vline.setAttribute('x1',x.toFixed(1));
    vline.setAttribute('x2',x.toFixed(1));
    vline.style.display='block';
  }
  historyTooltip(evt,label,best[1],unit);
}
function renderMiniHistory(entityId,pts){
