  const isCellDelta=/cell_voltage_delta/i.test(entityId);
  const isSoc=/(^|_)soc(_|$)|pourcentage|capacity|capacite/i.test(entityId)&&!isPower;
  const isSoh=/soh/i.test(entityId);
  const isCycle=/nombre_cycle|cycles?|cycle_/i.test(entityId);
  const isBatteryVoltage=/battery.*voltage|tension_totale_volt|global_battery_voltage|bat_voltage|bms_globales_tension_moyenne/i.test(lowEnt)&&!isBmsCellVoltage&&!isCellDelta;
  const isCurrent=/courant|current|ampere|_a$/i.test(entityId)&&!isPower;
