  if(configuredMaster){
    BMS_BROADCASTING = true;
    const out = new Set(['master']);
    configured.slice(1).forEach(x=>{const n=Number(x); if(n>1 && n<32) out.add(n)});
    numeric.forEach(n=>{if(n>1) out.add(n)});
