}
function archiveArr(period){
  const aliases={daily:['daily','day','days'],monthly:['monthly','month','months'],yearly:['yearly','year','years']};
  for(const a of (aliases[period]||[period])){
    const arr=normalizeArchive(entityAttr('sensor.smart_energy_finance_history_archive',a,[]));
