function v27UpdateInverterValues(){
 const pv=globalNum(E.pv,()=>sumInv('pv_total_power')), load=globalNum(E.load,()=>sumInv('ac_output_active_power')), grid=globalNum(E.grid,()=>sumInv('grid_power'));
