const V38_GET_BMS_IDS = `function getBmsIds(){
  const configured = (Array.isArray(BMS_SLOTS_FROM_CONFIG) ? BMS_SLOTS_FROM_CONFIG.slice() : []);
  const configuredMaster = configured.length && String(configured[0]).toLowerCase() === 'master';
  if(configuredMaster){
    BMS_BROADCASTING = true;
    return configured.sort((a,b)=>bmsSortKey(a)-bmsSortKey(b));
  }

  const all = Object.keys(STATES || {});
  const numeric = new Set();
  all.forEach(id=>{
    const m = id.match(/^(?:sensor|binary_sensor|number|switch)\.bms_(\d+)_/i);
    if(m){ const n = Number(m[1]); if(n>0 && n<32) numeric.add(n); }
  });

  const runtimeBroadcasting = detectBroadcastingMode();
  BMS_BROADCASTING = runtimeBroadcasting;

  if(runtimeBroadcasting){
    const maxFromConfigured = configured.filter(x=>Number(x)>1).map(Number);
    const max = Math.max(4, numeric.size ? Math.max(...numeric) : 0, maxFromConfigured.length ? Math.max(...maxFromConfigured) : 0);
    const out = ['master'];
    for(let i=2;i<=max;i++) out.push(i);
    return out;
  }

  if(configured.length){
    return configured.sort((a,b)=>bmsSortKey(a)-bmsSortKey(b));
  }
  if(numeric.size){
    return [...numeric].sort((a,b)=>a-b);
  }
  return [1,2,3,4];
}`;
html = html.replace(/function getBmsIds\(\)\{[\s\S]*?\}function mppt/, V38_GET_BMS_IDS + 'function mppt');

