      const u=new URL(location.href);
      const q=u.searchParams.get('open_bms_alarm')||u.searchParams.get('bms_alarm')||u.searchParams.get('bms');
      const h=String(location.hash||'');
      const hm=h.match(/(?:bms|open_bms_alarm|bms_alarm)=([^&]+)/i);
      const v=q|| (hm?decodeURIComponent(hm[1]):'');
      return v?String(v).replace(/[^0-9a-z_-]/gi,''):'';
    }catch(e){return ''}
  }
  function wantedFromStorage(){
    try{return localStorage.getItem('smart_energy_open_jk_alarm')||''}catch(e){return ''}
  }
  function activateAlarm(i){
    i=String(i||'').replace(/[^0-9a-z_-]/gi,'');
    if(!i)return false;
    let ok=false;
    try{
      const b=[...document.querySelectorAll('#main_nav .tab,button,a,[role="button"]')].find(x=>{
        const oc=x.getAttribute('onclick')||'';
        const tx=(x.textContent||'').trim();
        return oc.includes("showTab('jkbms'") || /JK\s*-?\s*BMS/i.test(tx);
      });
      if(typeof showTab==='function')showTab('jkbms',b);
      else if(b)b.click();
    }catch(e){}
    try{ if(typeof setBmsView==='function'){ setBmsView('battery',i); ok=true; } }catch(e){}
    try{ if(typeof setBmsTab==='function'){ setBmsTab(i,'alarms'); ok=true; } }catch(e){}
    try{ if(typeof updateBms==='function')updateBms(); }catch(e){}
    try{
      const btn=[...document.querySelectorAll('#jkbms .bms-detail-tab,[data-bms-detail]')].find(x=>{
        const d=String(x.getAttribute('data-bms-detail')||x.dataset?.bmsDetail||'');
        return d===String(i)+':alarms' || (/alarme|alarm/i.test(x.textContent||'') && (!d || d.startsWith(String(i)+':')));
      });
      if(btn){ btn.click(); ok=true; }
    }catch(e){}
    if(ok){try{localStorage.removeItem('smart_energy_open_jk_alarm')}catch(e){}}
